// glossary dataset - generated page entries. NO em-dash / en-dash, ASCII only.
// ~200 real CRM / sales / revenue / RevOps term definitions. Each entry is a
// live page at /pages/<slug> rendered by the SeoPage `glossary` template.
// Compact data below, expanded by .map() into full entries (see comparisons.js).
const PUB = '2026-07-10';

const kebab = (s) =>
  s.toLowerCase().replace(/[^a-z0-9]+/g, ' ').trim().replace(/\s+/g, '-');

// Each term: { term, def (40-60w shortAnswer), points[3-4], why, rally, faqs[2], slug? }
const TERMS = [
  // ---- Pipeline and deals ----
  { term: 'Sales Pipeline', def: `A sales pipeline is a visual, stage-by-stage view of every open deal a team is working, from first qualified conversation to signed contract. Each stage maps to a buyer milestone and each deal carries an amount and close date, so reps and leaders can total committed revenue and spot where deals stall.`,
    points: [`Deals are organized into named stages tied to real buyer milestones.`, `Every opportunity carries a value, owner, stage, and expected close date.`, `Coverage math (open pipeline divided by quota) shows if there is enough to hit the number.`, `Stalled deals sitting too long in one stage are the first warning sign.`],
    why: `The pipeline answers the two questions every revenue leader asks: are we going to hit the number, and if not, where is the gap. It is also the raw material for win rate, velocity, and forecast math.`,
    rally: `Rally ships a deep deal object with stages, amount, close date, and buying committee out of the box, so your pipeline is alive on day one. Rook keeps it clean, flags stalled deals, and updates stages from meeting notes.`,
    faqs: [{ q: `What is the difference between a pipeline and a funnel?`, a: `A pipeline tracks named open deals you are actively working, deal by deal. A funnel is an aggregate conversion view of what share of leads passes each step. Pipelines are operational, funnels are analytical.` }, { q: `How many stages should a pipeline have?`, a: `Most B2B teams use five to seven stages. Fewer than four hides signal, more than eight creates busywork. Each stage should map to a buyer milestone with a clear exit criterion.` }] },

  { term: 'Sales Funnel', def: `A sales funnel is an aggregate model of how prospects convert from awareness to purchase, narrowing at each step as some drop off. It measures the share of people who move from one stage to the next, revealing where the biggest leaks are so teams can focus fixes on the weakest conversion point.`,
    points: [`Models conversion rates between stages, not individual named deals.`, `Wide at the top (awareness), narrow at the bottom (purchase).`, `Highlights the single stage where the most prospects drop off.`, `Marketing and sales share the funnel to align on handoffs.`],
    why: `The funnel turns a vague sense of "we need more leads" into a specific diagnosis: if only 2 percent of demos close, more demos will not fix a closing problem. It focuses effort on the weakest link.`,
    rally: `Rally computes funnel conversion between every stage automatically from your live deal and lead data, so you see exactly where prospects leak. Rook can suggest which stage to fix first based on the biggest drop.`,
    faqs: [{ q: `Is a sales funnel the same as a marketing funnel?`, a: `They overlap. A marketing funnel covers awareness to lead, a sales funnel covers lead to closed deal. Many teams model one continuous funnel from first touch to revenue.` }, { q: `How do you calculate funnel conversion rate?`, a: `Divide the number that reach a stage by the number that entered the prior stage. If 100 leads produce 20 opportunities, the lead-to-opportunity rate is 20 percent.` }] },

  { term: 'Pipeline Coverage', def: `Pipeline coverage is the ratio of total open pipeline value to the sales quota for a period. A 3x coverage ratio means you have three dollars of open pipeline for every dollar of target. It tells leaders whether there is enough in play to hit the number after normal loss and slippage.`,
    points: [`Calculated as open pipeline value divided by the period quota.`, `A common healthy benchmark is 3x to 4x.`, `The right multiple depends on your win rate: lower win rate needs more coverage.`, `Thin coverage early in a quarter predicts a miss.`],
    why: `Coverage is the earliest leading indicator of whether a quarter will land. Leaders watch it weeks before close so they can push pipeline generation while there is still time to react.`,
    rally: `Rally calculates coverage live against each rep and team quota and shows it on the forecast view. Rook flags when coverage dips below your target multiple and suggests which accounts to work to close the gap.`,
    faqs: [{ q: `What is a good pipeline coverage ratio?`, a: `Three to four times quota is a common benchmark. Teams with a high win rate can run leaner coverage; teams with a low win rate need more to absorb losses.` }, { q: `Should coverage include all open deals?`, a: `Usually only deals expected to close in the period, weighted or unweighted depending on the team. Counting deals with far-future close dates inflates coverage and hides risk.` }] },

  { term: 'Weighted Pipeline', def: `Weighted pipeline multiplies each open deal's value by its probability of closing, then sums the results. A 50,000 dollar deal at 40 percent contributes 20,000 dollars. It produces a risk-adjusted revenue estimate that is more realistic than raw pipeline value for forecasting a period's likely bookings.`,
    points: [`Each deal value is multiplied by a close probability.`, `Probabilities usually come from the deal's stage or a scoring model.`, `Produces a risk-adjusted number between raw pipeline and zero.`, `More conservative and forecast-friendly than total open pipeline.`],
    why: `Raw pipeline overstates what will actually close; weighting corrects for it. It gives leaders a single realistic number to compare against quota without manually judging every deal.`,
    rally: `Rally weights pipeline by stage probability automatically and lets you override per deal. Rook refines the weighting with real signals like engagement and buying committee coverage, not just the stage a rep parked the deal in.`,
    faqs: [{ q: `Where do the probabilities come from?`, a: `Most teams assign a default win probability to each pipeline stage. More advanced setups use a model that scores each deal on engagement, fit, and history.` }, { q: `Is weighted pipeline the same as a forecast?`, a: `It is one input to a forecast, not the whole thing. Good forecasts also use rep commit judgment, historical accuracy, and category rollups alongside the weighted number.` }] },

  { term: 'Sales Velocity', def: `Sales velocity measures how fast a team turns pipeline into revenue. It multiplies the number of open deals by average deal value and win rate, then divides by the average sales cycle length in days. The result is dollars generated per day, and improving any of the four inputs raises it.`,
    points: [`Formula: (deals x average value x win rate) / cycle length in days.`, `Combines four levers into one dollars-per-day number.`, `Shorter cycles and higher win rates both raise velocity.`, `Useful for comparing teams, segments, or time periods.`],
    why: `Velocity turns four separate metrics into one figure leaders can track over time and by segment. It makes the tradeoffs visible: a bigger deal that takes twice as long may not actually help velocity.`,
    rally: `Rally computes velocity from your live deal data and breaks it down by rep, segment, and source. Rook highlights which of the four levers is dragging and where a small win-rate or cycle improvement would pay off most.`,
    faqs: [{ q: `What is the sales velocity formula?`, a: `Number of opportunities multiplied by average deal value multiplied by win rate, all divided by the average sales cycle length in days. It yields revenue generated per day.` }, { q: `How do you increase sales velocity?`, a: `Raise win rate, increase average deal size, add more qualified opportunities, or shorten the cycle. Shortening the cycle is often the fastest lever because it is in the denominator.` }] },

  { term: 'Sales Cycle', def: `A sales cycle is the average time from first qualified contact to a closed deal. It is measured in days and varies by deal size and complexity, from days for self-serve to many months for enterprise. Knowing your cycle length lets you forecast close dates and diagnose where deals slow down.`,
    points: [`Measured as average days from opportunity creation to close.`, `Longer for larger, more complex, multi-stakeholder deals.`, `Used to set realistic close dates and staffing plans.`, `A lengthening cycle can signal qualification or process problems.`],
    why: `Cycle length drives forecasting accuracy and cash timing. If reps set close dates that ignore the real cycle, the forecast slips quarter after quarter.`,
    rally: `Rally measures actual cycle length by segment from your closed deals, so close-date suggestions are grounded in reality. Rook warns when a deal's projected close date is unrealistic given its stage and your historical cycle.`,
    faqs: [{ q: `What is an average B2B sales cycle length?`, a: `It ranges widely: small transactional deals can close in days, mid-market in one to three months, and enterprise in six to twelve months or more. Measure your own rather than trusting a benchmark.` }, { q: `How do you shorten a sales cycle?`, a: `Qualify harder up front, multithread early, build a mutual action plan, and remove friction like slow legal or procurement steps. Disqualifying bad-fit deals sooner also shortens the average.` }] },

  { term: 'Win Rate', def: `Win rate is the percentage of qualified opportunities that end in a closed-won deal. If 100 opportunities produce 25 wins, the win rate is 25 percent. It is one of the most important sales metrics because small improvements compound directly into more revenue from the same pipeline.`,
    points: [`Calculated as closed-won deals divided by all closed deals (won plus lost).`, `Can be measured overall or by segment, source, rep, or stage.`, `A key input to sales velocity and pipeline coverage math.`, `Rising win rate means better qualification or better selling.`],
    why: `Win rate tells you how efficiently pipeline converts to revenue. Raising it means you need less pipeline for the same target, which lowers acquisition cost and coverage requirements.`,
    rally: `Rally tracks win rate by rep, source, segment, and stage so you can see exactly where deals are won and lost. Rook surfaces the traits of your winning deals so reps can replicate them.`,
    faqs: [{ q: `How is win rate calculated?`, a: `Divide closed-won deals by total closed deals in a period. Some teams include only qualified opportunities to avoid diluting the number with early-stage deals that were never real.` }, { q: `What is a good win rate?`, a: `It varies by market, but many B2B teams land between 15 and 30 percent. What matters more is the trend and how yours compares across segments and sources.` }] },

  { term: 'Close Rate', def: `Close rate is the share of leads or opportunities that convert into paying customers over a period. It is often used interchangeably with win rate, though close rate sometimes measures from an earlier point such as lead-to-customer. It gauges how effectively a team turns interest into revenue.`,
    points: [`Percentage of leads or opportunities that become customers.`, `Sometimes measured from lead, sometimes from qualified opportunity.`, `Higher close rates mean more efficient use of pipeline and effort.`, `Track by source and rep to find what and who converts best.`],
    why: `Close rate reveals selling efficiency and lead quality at once. A low close rate from a specific source usually means the leads are poorly qualified, not that reps are failing.`,
    rally: `Rally tracks close rate at every conversion point from lead to customer, broken out by source and owner. Rook flags sources whose leads look busy but rarely close so you stop spending on them.`,
    faqs: [{ q: `Is close rate the same as win rate?`, a: `Often, but not always. Win rate usually measures qualified opportunities to closed-won. Close rate is sometimes measured from an earlier point such as raw lead to customer, which produces a lower number.` }, { q: `How do you improve close rate?`, a: `Tighten qualification so only real deals enter the pipeline, handle objections earlier, and multithread to reach the economic buyer. Better leads plus better process both move the number.` }] },

  { term: 'Sales Stage', def: `A sales stage is a defined step in the pipeline that a deal occupies, each mapped to a buyer milestone with clear exit criteria. Typical stages include discovery, demo, proposal, negotiation, and closed. Stages give the team a shared language for where a deal stands and what has to happen next.`,
    points: [`Each stage represents a buyer milestone, not internal activity.`, `Every stage has an exit criterion that must be met to advance.`, `Stages often carry a default win probability for weighting.`, `Consistent stage definitions keep forecasts trustworthy.`],
    why: `Clear stage definitions are the foundation of an honest pipeline. When reps interpret stages differently, the forecast becomes noise. Exit criteria keep everyone consistent.`,
    rally: `Rally lets you define stages with explicit exit criteria and default probabilities, and Rook updates a deal's stage from meeting notes and activity so stages reflect reality instead of wishful data entry.`,
    faqs: [{ q: `What is a stage exit criterion?`, a: `A specific, verifiable condition a deal must meet to move to the next stage, such as "economic buyer confirmed" or "proposal sent". It keeps stage data consistent across reps.` }, { q: `Should stages be based on buyer or seller actions?`, a: `Buyer actions are more reliable. "Demo delivered" is a seller action; "buyer agreed to a proposal" reflects real progress. Buyer-based stages produce more accurate forecasts.` }] },

  { term: 'Opportunity', def: `An opportunity is a qualified potential deal that a rep is actively working toward a close. It carries an amount, an expected close date, a stage, and the people involved. Opportunities are the core records of a pipeline and the unit that sales forecasts are built from.`,
    points: [`A qualified, revenue-bearing deal in progress.`, `Carries amount, close date, stage, and associated contacts.`, `Created when a lead or account is qualified enough to pursue.`, `The primary object sales forecasts roll up from.`],
    why: `The opportunity is where forecasting, coaching, and revenue tracking all converge. Its data quality determines how trustworthy every downstream report is.`,
    rally: `Rally's opportunity object is deep by default: line items, buying committee, competitors, and next steps all live on the deal. Rook keeps the fields current and flags opportunities missing the data needed to forecast them.`,
    faqs: [{ q: `What is the difference between a lead and an opportunity?`, a: `A lead is an unqualified expression of interest. An opportunity is a qualified deal with a value and close date that a rep is actively working. Leads convert into opportunities.` }, { q: `When should you create an opportunity?`, a: `When a lead is qualified enough to justify real selling effort, typically after confirming fit, budget, and a genuine need. Creating opportunities too early inflates the pipeline.` }] },

  { term: 'Forecast Category', def: `A forecast category is a label that groups deals by confidence for revenue projection, independent of pipeline stage. Common categories are pipeline, best case, commit, and closed. They let a rep signal how sure they are a deal will land this period, which drives an accurate roll-up forecast.`,
    points: [`Groups deals by close confidence: pipeline, best case, commit, closed.`, `Separate from stage, which reflects buyer progress.`, `Commit means the rep is confident the deal closes this period.`, `Rolls up into the team forecast leaders present to the business.`],
    why: `Stage alone does not capture a rep's judgment about timing and risk. Forecast categories add that human confidence signal, producing a roll-up that leaders can actually commit to.`,
    rally: `Rally supports forecast categories on every deal and rolls them up by rep and team. Rook compares a rep's category choices against real engagement signals and flags deals in commit that do not look ready.`,
    faqs: [{ q: `What is the difference between stage and forecast category?`, a: `Stage reflects where the buyer is in their journey. Forecast category reflects how confident the rep is the deal closes in the period. A late-stage deal can still be only best case if timing is uncertain.` }, { q: `What does commit mean in forecasting?`, a: `Commit is the rep's promise that a deal will close in the current period. Commit deals form the floor of the forecast that leadership counts on.` }] },

  { term: 'Deal Desk', def: `A deal desk is a cross-functional team or process that reviews and approves complex, high-value, or non-standard deals before they close. It coordinates pricing, discounts, legal terms, and approvals so reps can move fast on hard deals without breaking policy or margin. It is common in enterprise sales.`,
    points: [`Reviews non-standard pricing, terms, and structure on complex deals.`, `Coordinates finance, legal, and leadership approvals.`, `Speeds up hard deals while protecting margin and policy.`, `Most valuable in enterprise and high-discount environments.`],
    why: `Without a deal desk, big non-standard deals get stuck bouncing between finance, legal, and management. A desk centralizes the review so reps get fast, consistent answers.`,
    rally: `Rally routes deals that trip discount or term thresholds into an approval workflow with a full audit trail, so the desk sees everything in one place. Rook drafts the approval summary from the deal's line items and history.`,
    faqs: [{ q: `When does a deal need to go through the deal desk?`, a: `Typically when it involves nonstandard discounts, custom legal terms, unusual payment schedules, or a size above a set threshold. Standard deals skip the desk to keep velocity high.` }, { q: `Who sits on a deal desk?`, a: `Usually representatives from sales operations, finance, legal, and sometimes product or leadership. The mix depends on what kinds of exceptions the business allows.` }] },

  { term: 'Mutual Action Plan', def: `A mutual action plan is a shared, dated checklist that a seller and buyer build together, listing every step needed to reach a decision and go live. It aligns both sides on owners, dates, and milestones, reducing surprises and slippage. It is a hallmark of well-run complex B2B deals.`,
    points: [`A jointly owned timeline of steps to close and implement.`, `Assigns owners and dates to each milestone on both sides.`, `Surfaces hidden steps like legal review and security review early.`, `Reduces slippage by making the path to signature explicit.`],
    why: `Complex deals slip because unspoken steps like procurement or security review appear late. A mutual action plan drags those steps into the open early so both sides can plan around them.`,
    rally: `Rally lets you attach a mutual action plan to a deal with owners and due dates, and Rook tracks progress, nudges owners on overdue steps, and warns when a slipping milestone puts the close date at risk.`,
    faqs: [{ q: `Why use a mutual action plan?`, a: `It aligns buyer and seller on exactly what must happen and when, exposing hidden steps early. Deals with a shared plan slip less and close more predictably than deals run from the seller's head.` }, { q: `When should you introduce one?`, a: `Usually after a successful demo or once the buyer signals real intent, when there is a clear path to a decision. Introducing it too early can feel presumptuous.` }] },

  { term: 'Sandbagging', def: `Sandbagging in sales is when a rep deliberately understates a deal's progress or likelihood, keeping it out of the commit forecast so they can beat expectations later. It distorts forecasts by hiding real pipeline. Managers watch for late-stage deals held in low forecast categories as a sign of it.`,
    points: [`Reps hide strong deals to under-promise and over-deliver.`, `Distorts the forecast by understating real committed revenue.`, `Often shows as late-stage deals stuck in low forecast categories.`, `The opposite of happy-ears optimism, but just as harmful to accuracy.`],
    why: `Sandbagging makes forecasts unreliable in the other direction: leaders under-plan resources or miss a chance to invest because the real pipeline is hidden. Accuracy, not optimism or pessimism, is the goal.`,
    rally: `Rally compares each deal's engagement signals against its forecast category, so Rook can flag a late-stage, highly engaged deal that a rep is parking in best case. That surfaces sandbagging without accusing anyone.`,
    faqs: [{ q: `Why do reps sandbag?`, a: `To create a cushion so they comfortably beat quota, to lower next-period targets, or to avoid pressure on deals they want to control. It is a rational response to how comp and expectations are set.` }, { q: `How do managers detect sandbagging?`, a: `Look for advanced-stage deals held in low-confidence categories, high buyer engagement paired with a pessimistic rep call, and a pattern of deals that suddenly close after being downplayed.` }] },

  { term: 'Deal Slippage', def: `Deal slippage is when an opportunity fails to close by its expected date and pushes into a later period. Chronic slippage wrecks forecast accuracy and signals qualification or process problems. Tracking slippage rate, the share of deals that move their close date, is a core forecasting discipline.`,
    points: [`A deal's close date pushing from one period into the next.`, `Chronic slippage destroys forecast accuracy.`, `Often caused by weak qualification or missing decision-maker access.`, `Slippage rate is a key metric to track and reduce.`],
    why: `A forecast is only as good as its close dates. If deals routinely slip, leadership plans hiring and spending on revenue that never arrives on time.`,
    rally: `Rally tracks how often each rep's deals slip and why, and Rook warns before a close date when a deal shows no recent buyer activity, giving reps time to re-engage or re-date honestly.`,
    faqs: [{ q: `What causes deals to slip?`, a: `Unconfirmed decision makers, no compelling event, missing budget approval, and optimistic close dates set to please a manager. Most slippage traces back to weak qualification earlier in the cycle.` }, { q: `How do you reduce slippage?`, a: `Qualify for a compelling event and real timeline, build a mutual action plan, multithread to the economic buyer, and set close dates from the actual cycle length rather than hope.` }] },

  { term: 'Bookings', def: `Bookings are the total value of contracts customers have committed to, signed in a given period, regardless of when the revenue is recognized or cash is collected. A one-year 60,000 dollar contract is a 60,000 dollar booking on signing. Bookings measure sales output, not accounting revenue.`,
    points: [`Total contract value signed in a period.`, `Recorded at signature, not as service is delivered.`, `Different from revenue, which is recognized over the contract term.`, `A primary measure of sales team output and quota attainment.`],
    why: `Bookings show what the sales team actually sold this period, before accounting spreads it out. Leaders use bookings to measure sales performance and to plan the revenue that will follow.`,
    rally: `Rally records bookings the moment a deal closes and ties them to the deal's line items, so sales output and downstream billing stay connected. Rook can break bookings down by product, segment, and rep instantly.`,
    faqs: [{ q: `What is the difference between bookings and revenue?`, a: `Bookings are the full value committed when a contract is signed. Revenue is recognized gradually as the product or service is delivered. A 12-month deal books fully on day one but recognizes revenue monthly.` }, { q: `Are bookings the same as billings?`, a: `No. Bookings are what the customer committed to. Billings are what you have invoiced so far. A customer can book a year but be billed monthly or quarterly.` }] },

  { term: 'Ramp Time', def: `Ramp time is how long it takes a newly hired sales rep to reach full productivity and carry a full quota. It typically spans one to six months depending on deal complexity. Knowing ramp time lets leaders plan hiring ahead of need and set fair, graduated quotas for new reps.`,
    points: [`Time from a rep's start date to full quota productivity.`, `Ranges from weeks in transactional sales to months in enterprise.`, `Drives hiring lead times and new-hire quota schedules.`, `Faster ramp means quicker payback on hiring cost.`],
    why: `If ramp takes five months, a rep hired in April will not fully contribute until fall. Leaders who ignore ramp hire too late and miss their number even with the right headcount plan.`,
    rally: `Rally is alive with data on day one, so new reps inherit real pipeline and playbooks instead of a blank CRM. Rook coaches new hires through the process, which shortens ramp measurably.`,
    faqs: [{ q: `What is a typical sales ramp time?`, a: `Transactional roles can ramp in weeks; mid-market in two to four months; enterprise in six months or more. Complexity, deal size, and cycle length are the main drivers.` }, { q: `How do you shorten ramp time?`, a: `Give new reps warm pipeline, clear playbooks and battlecards, structured onboarding, and fast feedback. Tools that surface next best actions cut the time to competence.` }] },

  { term: 'Pipeline Generation', def: `Pipeline generation, often shortened to pipegen, is the ongoing work of creating new qualified opportunities to fill the pipeline. It spans outbound prospecting, inbound marketing, partnerships, and events. Because deals constantly leave the pipeline as won or lost, consistent pipeline generation is what keeps a team hitting future quotas.`,
    points: [`The work of adding new qualified opportunities to the pipeline.`, `Sources include outbound, inbound, partners, and events.`, `Must be continuous because deals always exit the pipeline.`, `Measured as new pipeline dollars created per period.`],
    why: `Todays revenue comes from pipeline built weeks or months ago. Teams that neglect pipeline generation feel fine now and starve two quarters later. It is the leading indicator of future bookings.`,
    rally: `Rally tracks new pipeline created by source and rep so leaders can see who is building and who is coasting. Rook runs outbound sequences and surfaces intent signals to help reps generate pipeline efficiently.`,
    faqs: [{ q: `How much pipeline do you need to generate?`, a: `Enough to maintain your target coverage ratio after loss and slippage. If you close a quarter of deals and want 3x coverage, you need to generate roughly twelve times your quota over the cycle.` }, { q: `Whose job is pipeline generation?`, a: `Shared. Marketing drives inbound, SDRs and reps drive outbound, and partnerships add another channel. Healthy teams do not rely on a single source.` }] },


  // ---- Qualification frameworks ----
  { term: 'MEDDIC', def: `MEDDIC is a B2B sales qualification framework built on six checks: Metrics, Economic buyer, Decision criteria, Decision process, Identify pain, and Champion. Reps use it to qualify complex deals rigorously, confirming they understand the buyer's math, power structure, and internal process before investing in a long sales cycle.`,
    points: [`Six elements: Metrics, Economic buyer, Decision criteria, Decision process, Identify pain, Champion.`, `Designed for complex, high-value enterprise deals.`, `Forces reps to confirm buyer power, process, and pain before advancing.`, `Improves forecast accuracy by exposing gaps early.`],
    why: `MEDDIC catches the deals that feel good but are missing something fatal, like no economic buyer or no real pain. Filling the gaps early is what separates a strong forecast from a hopeful one.`,
    rally: `Rally can store MEDDIC fields directly on the deal object so qualification is visible, not tribal. Rook flags deals advancing in stage while key MEDDIC elements like economic buyer or metrics are still blank.`,
    faqs: [{ q: `What does MEDDIC stand for?`, a: `Metrics, Economic buyer, Decision criteria, Decision process, Identify pain, and Champion. Each is a question a rep must answer before trusting that a complex deal is real and forecastable.` }, { q: `When should you use MEDDIC?`, a: `In complex, high-value B2B deals with multiple stakeholders and long cycles. For simple transactional sales its rigor is overkill; a lighter framework like BANT fits better.` }] },

  { term: 'MEDDPICC', def: `MEDDPICC extends the MEDDIC qualification framework with two more checks: Paper process and Competition. The full set is Metrics, Economic buyer, Decision criteria, Decision process, Paper process, Identify pain, Champion, and Competition. The additions force reps to plan for contracting and legal steps and to know where they stand against rivals.`,
    points: [`MEDDIC plus Paper process and Competition.`, `Paper process covers legal, procurement, and signature steps.`, `Competition forces an honest read of the competitive position.`, `Even more suited to large, complex enterprise deals.`],
    why: `Big deals slip on paperwork and lose to unseen competitors. MEDDPICC makes both explicit so reps plan for legal review early and defend against rivals rather than being surprised at the finish line.`,
    rally: `Rally stores the full MEDDPICC scorecard on the deal, including a competitors list. Rook tracks paper-process steps as milestones and warns when contracting is likely to become the bottleneck.`,
    faqs: [{ q: `What is the difference between MEDDIC and MEDDPICC?`, a: `MEDDPICC adds two elements MEDDIC lacks: Paper process (legal and procurement steps) and Competition (your position against rivals). Both address common late-stage reasons enterprise deals slip or are lost.` }, { q: `Is MEDDPICC better than MEDDIC?`, a: `Not universally. MEDDPICC is more thorough for the largest, most contested deals. For deals with simpler contracting or no real competition, the extra rigor adds work without adding insight.` }] },

  { term: 'BANT', def: `BANT is a classic sales qualification framework covering Budget, Authority, Need, and Timeline. A rep checks whether the prospect has money to spend, the power to buy, a genuine need, and a timeframe to act. It is simple and fast, best suited to shorter, less complex sales cycles.`,
    points: [`Four checks: Budget, Authority, Need, Timeline.`, `Fast and easy to apply, popular for inbound qualification.`, `Best for transactional and mid-market deals, not complex enterprise.`, `Criticized for being seller-centric rather than buyer-centric.`],
    why: `BANT gives reps a quick filter to avoid wasting time on prospects who cannot or will not buy. Its simplicity is the appeal and the limitation: it misses the nuance of multi-stakeholder deals.`,
    rally: `Rally can capture BANT answers on the lead or deal so qualification is consistent across reps. Rook can ask BANT questions during inbound triage and route only genuinely qualified leads to sellers.`,
    faqs: [{ q: `What does BANT stand for?`, a: `Budget, Authority, Need, and Timeline. If a prospect has all four, they are generally worth pursuing. Missing one signals a deal that may stall or never close.` }, { q: `Is BANT outdated?`, a: `It is dated for complex sales because it centers the seller's checklist over the buyer's journey and assumes a single decision maker. It still works well for fast, transactional qualification.` }] },

  { term: 'CHAMP', def: `CHAMP is a sales qualification framework that leads with the customer's problem. It stands for Challenges, Authority, Money, and Prioritization. By starting with challenges rather than budget, CHAMP encourages a consultative discovery that uncovers real pain first, then confirms the buyer can act on it.`,
    points: [`Four elements: Challenges, Authority, Money, Prioritization.`, `Leads with the buyer's problem, not the seller's budget question.`, `A more buyer-centric alternative to BANT.`, `Prioritization checks where solving this ranks against other initiatives.`],
    why: `Opening with challenges builds trust and surfaces the pain that actually drives a purchase. Prioritization then reveals whether the buyer will act now or leave the deal to drift, which BANT often misses.`,
    rally: `Rally captures CHAMP discovery notes on the deal and Rook can summarize a discovery call into Challenges, Authority, Money, and Prioritization automatically, so qualification is recorded without manual data entry.`,
    faqs: [{ q: `How is CHAMP different from BANT?`, a: `CHAMP reorders the priorities to lead with Challenges instead of Budget, making discovery more consultative. It also swaps Timeline for Prioritization, which asks how urgent solving the problem really is.` }, { q: `When should you use CHAMP?`, a: `When a consultative, problem-first discovery fits your market, particularly where buyers may not have a formal budget yet but have a pressing challenge worth solving.` }] },

  { term: 'SPIN Selling', def: `SPIN Selling is a questioning methodology from Neil Rackham based on four question types: Situation, Problem, Implication, and Need-payoff. Reps guide buyers from understanding their situation to feeling the cost of a problem and the value of solving it, which works especially well in larger, consultative sales.`,
    points: [`Four question types: Situation, Problem, Implication, Need-payoff.`, `Moves buyers from awareness of a problem to desire for a solution.`, `Grounded in research on thousands of real sales calls.`, `Best for complex, consultative B2B selling.`],
    why: `SPIN works because implication questions make buyers feel the real cost of inaction, and need-payoff questions let them articulate the value themselves. Buyers persuade themselves rather than being pitched.`,
    rally: `Rally can prompt SPIN question flows in call plans and Rook can analyze recorded discovery calls to check whether reps asked implication and need-payoff questions or jumped straight to a pitch.`,
    faqs: [{ q: `What does SPIN stand for?`, a: `Situation, Problem, Implication, and Need-payoff. These are four escalating categories of questions that move a buyer from describing their context to wanting a solution.` }, { q: `Why are implication questions important?`, a: `They expand a small problem into its full business cost, building urgency. Without implication questions, buyers acknowledge a problem but do not feel enough pain to prioritize solving it.` }] },

  { term: 'Challenger Sale', def: `The Challenger Sale is a methodology arguing the best reps teach buyers something new, tailor the message to each stakeholder, and take control of the conversation. Rather than building rapport and reacting, Challengers reframe how a buyer sees their problem, offering a commercial insight that leads to the seller's strengths.`,
    points: [`Best reps teach, tailor, and take control.`, `Leads with a reframing commercial insight, not a feature list.`, `Based on research into what separates top performers.`, `Suited to complex sales where buyers face many options.`],
    why: `In crowded markets, buyers value a seller who changes how they think about the problem more than one who simply answers questions. The Challenger approach differentiates on insight rather than relationship alone.`,
    rally: `Rally can store tailored insights and battlecards by persona so reps have the teaching material ready. Rook surfaces the right reframe for each stakeholder based on the deal's buying committee.`,
    faqs: [{ q: `What are the Challenger profiles?`, a: `Research identified five rep types: Challenger, Hard Worker, Relationship Builder, Lone Wolf, and Problem Solver. Challengers most often outperform, especially on complex deals, by teaching and pushing.` }, { q: `Does the Challenger model replace relationships?`, a: `No. It argues that insight and constructive tension win more than rapport alone, but trust still matters. The point is to lead with value and challenge assumptions, not to be adversarial.` }] },

  { term: 'Sandler Selling System', def: `The Sandler Selling System is a methodology emphasizing mutual qualification, where the seller and buyer decide together whether there is a fit. It uses an up-front contract to set expectations, focuses on uncovering pain and budget early, and aims to prevent unpaid consulting and drawn-out deals that never close.`,
    points: [`Buyer and seller qualify each other as equals.`, `Up-front contracts set clear expectations for each meeting.`, `Emphasizes uncovering pain, budget, and decision process early.`, `Designed to avoid chasing deals that will not close.`],
    why: `Sandler protects the rep's time by disqualifying bad-fit deals early and by setting expectations so meetings end with a clear next step, not a vague "let me think about it".`,
    rally: `Rally records up-front contract terms and qualification notes on the deal, and Rook flags opportunities that keep advancing without a confirmed next step, the classic sign of a Sandler mismatch.`,
    faqs: [{ q: `What is an up-front contract in Sandler?`, a: `A mutual agreement at the start of a meeting about its purpose, agenda, time, and the possible outcomes, including a clear no. It prevents ambiguous endings and wasted follow-ups.` }, { q: `Who is Sandler selling best for?`, a: `Reps and teams that lose time to prospects who will not commit. Its disqualification discipline suits consultative sales where a long cycle makes chasing dead deals expensive.` }] },

  { term: 'Solution Selling', def: `Solution selling is a methodology that focuses on diagnosing a customer's problem and presenting a tailored combination of products and services as the remedy, rather than pushing features. The rep acts as a consultant, leading with the buyer's pain and business outcomes, which suits complex products with configurable value.`,
    points: [`Sells outcomes and remedies, not product features.`, `Rep diagnoses the problem before prescribing a solution.`, `Fits complex, configurable, or high-consideration products.`, `Requires strong discovery and business acumen.`],
    why: `Buyers do not want products, they want problems solved. Framing the sale around their pain and desired outcome makes the value obvious and the price easier to justify.`,
    rally: `Rally's deep deal object captures the diagnosed pain, desired outcomes, and the tailored solution, so the whole team sees the why behind a deal. Rook can assemble the outcome-based proposal in Studio.`,
    faqs: [{ q: `How is solution selling different from product selling?`, a: `Product selling leads with features and specs. Solution selling leads with the buyer's problem and frames the product as the remedy, tailoring the offer to their specific situation and outcomes.` }, { q: `When does solution selling work best?`, a: `With complex, configurable, or expensive products where value depends on the buyer's context. For simple commodity purchases the diagnostic overhead is unnecessary.` }] },

  { term: 'Consultative Selling', def: `Consultative selling is an approach where the rep acts as a trusted advisor, asking questions and offering expertise to help the buyer make a good decision, rather than pushing a product. It builds trust through genuine problem-solving and works well for complex, high-stakes purchases where buyers value guidance.`,
    points: [`Rep behaves as an advisor, not a pitchman.`, `Centers on questions, listening, and genuine expertise.`, `Builds trust that shortens future cycles and drives referrals.`, `Best for complex, high-consideration purchases.`],
    why: `Buyers making a big, risky decision want a guide they trust. Consultative selling earns that trust, which wins the deal and often the renewal and referral that follow.`,
    rally: `Rally gives reps the full context to advise well: account history, prior conversations, and buying committee all on the deal. Rook briefs the rep before each call so the guidance is informed, not generic.`,
    faqs: [{ q: `What skills does consultative selling require?`, a: `Strong questioning and active listening, genuine domain expertise, business acumen to connect the product to outcomes, and the patience to prioritize the buyer's decision over a quick close.` }, { q: `Is consultative selling slower?`, a: `Each deal may take more discovery, but trust reduces stalls, objections, and negotiation friction. Over time it often produces higher win rates, larger deals, and more referrals.` }] },
  // ---- Leads and funnel ----
  { term: 'Lead', def: `A lead is a person or organization that has shown some interest in your product but has not yet been qualified as a real buyer. Leads come from forms, events, lists, and outreach. They sit at the top of the funnel and are worked or scored to find the few worth pursuing.`,
    points: [`An unqualified expression of interest in your product.`, `Sourced from inbound forms, events, outbound, and lists.`, `Scored or graded to separate the promising from the noise.`, `Converts into a contact plus an opportunity once qualified.`],
    why: `Leads are the raw fuel of the pipeline, but raw volume is a vanity metric. What matters is how many convert to real opportunities, which is why scoring and qualification exist.`,
    rally: `Rally captures leads from forms and imports, enriches them with firmographic data, and scores them so the hottest sit at the top. Rook routes new leads to the right owner and starts the first-touch sequence.`,
    faqs: [{ q: `What makes a good lead?`, a: `Fit with your ideal customer profile plus a genuine signal of interest or need. A big-name company that downloaded one white paper on a whim is a worse lead than a perfect-fit account requesting a demo.` }, { q: `Where do leads come from?`, a: `Inbound web forms, content downloads, webinars, events, outbound prospecting, referrals, and purchased or partner lists. Conversion rates vary widely by source, so tracking source quality matters.` }] },

  { term: 'Lead vs Contact', def: `A lead and a contact are two record types in a CRM. A lead is an unqualified, often standalone person who has shown early interest. A contact is a person tied to an account you are actively selling to or already serving. Converting a qualified lead usually creates a contact plus an opportunity.`,
    points: [`A lead is unqualified; a contact is tied to a real account.`, `Leads live at the top of funnel, contacts inside active deals.`, `Converting a lead typically produces a contact and an opportunity.`, `Keeping them distinct protects reporting and pipeline hygiene.`],
    why: `Mixing leads and contacts corrupts reporting: you cannot tell top-of-funnel interest from real buying relationships. Clean separation keeps conversion metrics and pipeline data honest.`,
    rally: `Rally keeps leads and contacts as distinct objects and handles conversion cleanly, carrying context forward without duplication. Rook can match a new lead to an existing account so you avoid orphan records.`,
    faqs: [{ q: `When does a lead become a contact?`, a: `When it is qualified enough to associate with a specific account and pursue as business. Conversion generally creates a contact record and, if there is a deal, an opportunity too.` }, { q: `Can you skip leads and use only contacts?`, a: `Some teams do, treating every person as a contact and using status fields instead. It simplifies the model but can blur the line between raw interest and real relationships.` }] },

  { term: 'Lead Scoring', def: `Lead scoring assigns each lead a numeric value based on fit and behavior, so reps know which to work first. Fit points come from firmographics like industry and size; behavior points come from actions like demo requests or pricing-page visits. A high total flags a lead ready for sales.`,
    points: [`Combines fit (who they are) and behavior (what they do) into a score.`, `Higher scores signal higher likelihood and readiness to buy.`, `Lets reps prioritize the few leads worth immediate attention.`, `Thresholds trigger handoff from marketing to sales.`],
    why: `Reps cannot work every lead. Scoring focuses limited selling time on the leads most likely to convert, raising efficiency and keeping hot leads from going cold in a queue.`,
    rally: `Rally scores leads on fit and behavior automatically and surfaces the hottest at the top of the list. Rook can adjust weights based on which scored leads actually closed, so the model improves over time.`,
    faqs: [{ q: `What factors go into a lead score?`, a: `Fit factors such as industry, company size, role, and location, plus behavioral signals like email engagement, site visits, content downloads, and demo requests. Negative signals such as a personal email domain can subtract points.` }, { q: `What is the difference between lead scoring and grading?`, a: `Scoring often blends fit and behavior into one number. Grading usually rates fit alone on a letter scale. Some teams use both: a grade for fit and a score for engagement.` }] },

  { term: 'Lead Grading', def: `Lead grading rates how well a lead matches your ideal customer profile, usually on a letter scale from A to F. Grading focuses on fit, who the lead is, separate from behavior. An A-grade lead is a perfect-fit account, while an F is out of market regardless of how much interest they show.`,
    points: [`Rates fit against the ideal customer profile, often A to F.`, `Focused on who the lead is, not what they have done.`, `Often paired with a behavioral score for a full picture.`, `Prevents reps chasing engaged but poor-fit leads.`],
    why: `An enthusiastic lead who will never be a good customer wastes rep time. Grading catches poor fit early so effort goes to accounts that can actually become valuable customers.`,
    rally: `Rally grades leads against your defined ideal customer profile using enriched firmographic data, and pairs the grade with an engagement score so reps instantly see both fit and interest on one record.`,
    faqs: [{ q: `How is lead grading calculated?`, a: `By comparing a lead's firmographic attributes such as industry, size, and role against your ideal customer profile. Close matches earn high grades; mismatches earn low ones regardless of engagement.` }, { q: `Should you work a high-engagement, low-grade lead?`, a: `Usually not with a full sales effort. They may be researchers, students, or competitors. A nurture track fits better than a rep's time until fit improves.` }] },

  { term: 'Lead Nurturing', def: `Lead nurturing is the process of building relationships with leads who are not yet ready to buy, through relevant content and touches over time, until they become sales-ready. It keeps your brand present during a long consideration period so that when the buyer is ready, you are the obvious choice.`,
    points: [`Ongoing, relevant touches for leads not yet ready to buy.`, `Keeps your brand present through a long consideration window.`, `Usually automated via email sequences and content.`, `Converts patient nurturing into sales-ready leads over time.`],
    why: `Most leads are not ready to buy the day they enter your funnel. Nurturing captures that future demand instead of discarding it, turning slow leads into pipeline months later.`,
    rally: `Rally runs nurture sequences and tracks engagement so a lead automatically re-enters the sales queue when it heats up. Rook can tailor nurture content to each lead's interests and stage.`,
    faqs: [{ q: `How long should lead nurturing last?`, a: `As long as the buying cycle for your product, which can be weeks to over a year. The goal is to stay relevant until the lead shows real buying intent, then hand off to sales.` }, { q: `What content works for nurturing?`, a: `Educational material that helps the buyer regardless of purchase: guides, case studies, benchmarks, and webinars. Heavy sales pitches early in nurturing tend to push not-yet-ready buyers away.` }] },

  { term: 'MQL', def: `An MQL, or marketing qualified lead, is a lead that marketing judges ready for sales attention based on fit and engagement, but that sales has not yet accepted. It typically clears a lead-score threshold. The MQL is the formal handoff point where marketing passes a promising lead to the sales team.`,
    points: [`A marketing qualified lead ready to hand to sales.`, `Usually defined by crossing a lead-score threshold.`, `Marks the marketing-to-sales handoff in the funnel.`, `MQL-to-SQL conversion rate measures lead quality.`],
    why: `The MQL is where marketing and sales either align or fight. A clear, shared MQL definition prevents sales from ignoring leads and marketing from claiming credit for junk.`,
    rally: `Rally tracks MQL status and the conversion rate from MQL to accepted and qualified, so both teams see whether the handoff is producing revenue. Rook flags MQLs sitting untouched past the agreed response window.`,
    faqs: [{ q: `What makes a lead an MQL?`, a: `Meeting the criteria marketing and sales agreed on, usually a combination of good fit and enough engagement, expressed as a lead-score threshold. The exact bar should be tuned to what actually converts.` }, { q: `What is the difference between an MQL and an SQL?`, a: `An MQL is qualified by marketing and handed over. An SQL is a lead sales has accepted and confirmed worth pursuing. The gap between them measures how well marketing's bar predicts real opportunities.` }] },

  { term: 'SQL', def: `An SQL, or sales qualified lead, is a lead that a salesperson has reviewed, accepted, and judged worth active pursuit as a potential deal. It sits one step past the MQL. Reaching SQL status means both fit and intent are strong enough to justify a rep's time creating an opportunity.`,
    points: [`A lead sales has accepted and deemed worth pursuing.`, `One stage past the marketing qualified lead (MQL).`, `Confirms both fit and buying intent are strong.`, `Often converts directly into an opportunity.`],
    why: `The SQL is the real bridge from marketing effort to pipeline. Tracking how many MQLs become SQLs shows whether marketing's leads are genuinely sales-ready or just meeting a score threshold.`,
    rally: `Rally records the SQL step and measures MQL-to-SQL and SQL-to-opportunity conversion, so you see exactly where lead quality holds up or breaks down. Rook can auto-create the opportunity when a rep accepts an SQL.`,
    faqs: [{ q: `Who decides a lead is an SQL?`, a: `Sales does. A rep or SDR reviews the marketing qualified lead and confirms it is worth pursuing based on fit, timing, and intent. That acceptance is what turns an MQL into an SQL.` }, { q: `Is an SQL the same as an opportunity?`, a: `Close but not identical. An SQL is an accepted, sales-ready lead. An opportunity is a created deal with a value and close date. An SQL usually converts into an opportunity right after acceptance.` }] },

  { term: 'PQL', def: `A PQL, or product qualified lead, is a user who has experienced real value in a product, usually through a free trial or freemium plan, and shows signals that they are ready to buy. PQLs are central to product-led growth, where usage behavior, not a form fill, indicates readiness for a sales conversation.`,
    points: [`A lead qualified by real product usage, not just interest.`, `Common in product-led and freemium go-to-market models.`, `Usage signals like hitting limits indicate buying readiness.`, `Tends to convert far better than a marketing qualified lead.`],
    why: `A user who already relies on your product is a warmer prospect than someone who downloaded an ebook. PQLs let sales focus on people who have proven the value themselves.`,
    rally: `Rally can ingest product usage signals and score PQLs alongside traditional leads, so sales sees who is hitting limits or inviting teammates. Rook can trigger outreach the moment a user crosses a value threshold.`,
    faqs: [{ q: `What signals qualify a PQL?`, a: `Reaching a usage milestone, hitting a plan limit, inviting teammates, using a premium feature, or sustained active use. The best signals correlate with users who later paid, learned from your own data.` }, { q: `How is a PQL different from an MQL?`, a: `An MQL is qualified by marketing engagement like content and email. A PQL is qualified by hands-on product usage. PQLs generally convert at higher rates because the user has already felt the value.` }] },

  { term: 'Lead Routing', def: `Lead routing is the automated process of assigning incoming leads to the right salesperson based on rules like territory, industry, deal size, or round-robin balance. Fast, accurate routing means leads reach an owner within minutes, which sharply improves the odds of connecting and converting them.`,
    points: [`Auto-assigns leads to owners by defined rules.`, `Rules include territory, segment, size, and round-robin.`, `Speed to first touch strongly affects conversion.`, `Prevents leads from sitting unclaimed or double-worked.`],
    why: `Studies consistently show that responding within minutes beats responding within hours by a wide margin. Routing removes the delay and confusion of manual assignment so leads get worked fast.`,
    rally: `Rally routes new leads to the right owner instantly by your rules, and Rook can act on them immediately with a first-touch sequence, so speed to lead does not depend on a rep being at their desk.`,
    faqs: [{ q: `Why does lead routing speed matter so much?`, a: `The odds of qualifying a lead drop sharply after the first few minutes. Fast routing plus fast follow-up dramatically raises connect and conversion rates compared with leads that wait hours or days.` }, { q: `What rules are used to route leads?`, a: `Common rules include geographic territory, industry or segment, company size, product interest, existing account ownership, and round-robin distribution to balance load across reps.` }] },

  { term: 'Lead Enrichment', def: `Lead enrichment automatically adds missing data to a lead record, such as company size, industry, revenue, technologies used, and job title, by matching it against external data sources. Enriched leads can be scored, graded, and routed accurately, and reps get context before the first conversation instead of starting blind.`,
    points: [`Fills in firmographic and contact data on thin lead records.`, `Draws from third-party data sources matched to the lead.`, `Enables accurate scoring, grading, and routing.`, `Gives reps context before the first outreach.`],
    why: `A lead that submits only a name and email is nearly useless until enriched. Adding firmographics turns it into something you can qualify, prioritize, and personalize outreach around.`,
    rally: `Rally enriches leads on capture with firmographic and technographic data, so scoring and routing work from a complete picture. Rook uses the enriched context to personalize the first message.`,
    faqs: [{ q: `What data does lead enrichment add?`, a: `Typically company size, industry, revenue, location, technologies in use, and refined job title or seniority. Some providers add intent signals and social profiles too.` }, { q: `Is enriched data always accurate?`, a: `No data source is perfect; coverage and freshness vary by provider and region. Enrichment should be treated as a strong starting signal, verified during real conversations.` }] },

  { term: 'Inbound Lead', def: `An inbound lead is a prospect who reaches out to you first, drawn in by content, search, ads, referrals, or word of mouth. Because they initiate contact, inbound leads usually have some awareness and intent already, which tends to make them warmer and cheaper to convert than outbound leads.`,
    points: [`The prospect initiates contact with you.`, `Driven by content, SEO, ads, and referrals.`, `Generally warmer and higher intent than outbound.`, `Volume depends on marketing and brand investment.`],
    why: `Inbound leads scale with content and brand rather than headcount, and they arrive with intent. A strong inbound engine lowers acquisition cost and shortens cycles.`,
    rally: `Rally captures inbound leads from forms, scores and routes them instantly, and tracks which content and channels produce leads that actually close. Rook responds fast so inbound intent does not cool off.`,
    faqs: [{ q: `Are inbound leads better than outbound leads?`, a: `Inbound leads usually convert at higher rates and cost less per deal because they arrive with intent. Outbound reaches accounts that never would have found you, so most teams need both.` }, { q: `How do you generate more inbound leads?`, a: `Invest in content and SEO, run targeted ads, build brand and community, and make it easy to request a demo or trial. Referrals and word of mouth compound inbound over time.` }] },

  { term: 'Outbound Lead', def: `An outbound lead is a prospect that your team proactively reaches out to, rather than one who came to you. Outbound leads are generated through cold email, calls, and social outreach to a targeted list. They let you pursue specific ideal accounts even if those accounts have never heard of you.`,
    points: [`Generated by your team reaching out first.`, `Uses cold email, calls, and social outreach to a target list.`, `Lets you pursue specific ideal accounts on demand.`, `Colder than inbound, so it requires strong targeting and messaging.`],
    why: `Outbound gives you control: you can go straight after the accounts you most want rather than waiting for them to find you. It is essential for account-based strategies and predictable pipeline.`,
    rally: `Rally runs outbound sequences across email and calls, tracks responses, and links every outbound lead to its target account. Rook drafts personalized outreach and works the sequence so reps focus on live conversations.`,
    faqs: [{ q: `How are outbound leads generated?`, a: `By building a target list of ideal accounts and contacts, then reaching them with cold email, phone, and social touches in a coordinated sequence. Enrichment and personalization raise response rates.` }, { q: `Are outbound leads worth the effort?`, a: `Yes when targeting is tight. Outbound lets you reach exactly the accounts you want and creates predictable pipeline, though it costs more per lead and needs strong messaging to break through.` }] },

  { term: 'Top of Funnel', def: `Top of funnel, or TOFU, is the awareness stage where potential buyers first learn a problem or your brand exists. Activity here is broad and educational: content, ads, and social reach a wide audience. The goal is not to sell yet but to attract and capture interest that can be nurtured downward.`,
    points: [`The awareness stage at the widest part of the funnel.`, `Broad, educational content rather than product pitches.`, `Goal is to attract and capture interest, not close.`, `Feeds the middle and bottom of the funnel over time.`],
    why: `Nothing converts at the bottom of the funnel without enough entering at the top. A healthy top of funnel is what guarantees pipeline months from now.`,
    rally: `Rally ties top-of-funnel sources to eventual revenue, so you learn which awareness channels produce customers, not just clicks. Rook helps qualify and nurture the interest TOFU captures.`,
    faqs: [{ q: `What content works at the top of the funnel?`, a: `Educational, problem-focused material: blog posts, guides, videos, social content, and ads that raise awareness. It should help the audience understand a problem, not pitch your product.` }, { q: `How do you measure top of funnel?`, a: `Reach, traffic, new leads captured, and eventually the share of those leads that convert downstream. Tying TOFU activity to closed revenue is the real test of quality.` }] },

  { term: 'Middle of Funnel', def: `Middle of funnel, or MOFU, is the consideration stage where prospects are evaluating options to solve a problem they now understand. Content here is more specific: case studies, comparisons, webinars, and demos that build trust and show fit. The goal is to move interested leads toward becoming sales-ready.`,
    points: [`The consideration stage between awareness and decision.`, `Content includes case studies, comparisons, and webinars.`, `Builds trust and demonstrates fit for the buyer's problem.`, `Moves leads from curious to sales-ready.`],
    why: `The middle is where buyers decide whether you belong on the shortlist. Weak middle-of-funnel content loses prospects who were aware but not yet convinced you fit.`,
    rally: `Rally tracks middle-of-funnel engagement per lead and triggers sales handoff when interest crosses the threshold. Rook can serve the right case study or comparison based on the lead's stage and industry.`,
    faqs: [{ q: `What is the goal of middle-of-funnel content?`, a: `To help evaluating buyers see that you fit their specific problem and to build enough trust that they engage with sales. It bridges broad awareness and a concrete buying decision.` }, { q: `What content fits the middle of the funnel?`, a: `Case studies, product comparisons, ROI calculators, webinars, detailed guides, and demos. It is more specific and solution-oriented than top-of-funnel awareness content.` }] },

  { term: 'Bottom of Funnel', def: `Bottom of funnel, or BOFU, is the decision stage where a qualified buyer is close to purchasing and comparing final options. Activity here is sales-led and specific: proposals, pricing, trials, references, and negotiation. The goal is to remove remaining doubts and convert the opportunity into a closed deal.`,
    points: [`The decision stage nearest to purchase.`, `Sales-led: proposals, pricing, trials, and references.`, `Goal is to remove final objections and close.`, `Highest-intent, lowest-volume part of the funnel.`],
    why: `Deals are won or lost at the bottom. Small friction here, slow proposals, weak references, unclear pricing, loses buyers who were ready to say yes.`,
    rally: `Rally supports the bottom of the funnel with quotes, CPQ, proposals in Studio, and a clear approval flow, so nothing stalls at the finish. Rook keeps the deal moving and flags risks before close.`,
    faqs: [{ q: `What content and actions help at the bottom of the funnel?`, a: `Tailored proposals, clear pricing, free trials or pilots, customer references, security and legal docs, and responsive negotiation. Anything that removes doubt and friction helps close.` }, { q: `Why do deals stall at the bottom of the funnel?`, a: `Common causes are slow proposals, unresolved objections, missing economic-buyer buy-in, and procurement or legal delays. A mutual action plan and multithreading reduce these stalls.` }] },

  { term: 'Demand Generation', def: `Demand generation is the marketing discipline of creating awareness and interest in your product across the whole funnel, so that future buyers know and trust you before they are ready to purchase. Unlike lead generation, which captures contacts now, demand gen builds the market that later becomes pipeline.`,
    points: [`Creates awareness and trust across the full funnel.`, `Broader and longer-term than lead capture.`, `Builds the future market that becomes pipeline.`, `Measured by pipeline influenced, not just form fills.`],
    why: `Most of your future buyers are not in-market today. Demand generation builds recognition and trust now so that when they enter the market, you are already a contender.`,
    rally: `Rally connects demand-gen activity to influenced pipeline and revenue, so marketing can prove impact beyond raw lead counts. Rook helps convert the demand into qualified opportunities as buyers heat up.`,
    faqs: [{ q: `What is the difference between demand generation and lead generation?`, a: `Demand generation builds broad awareness and interest over time; lead generation captures specific contacts now. Lead gen harvests demand, demand gen creates it. Healthy programs invest in both.` }, { q: `How do you measure demand generation?`, a: `By pipeline and revenue influenced, brand and search lift, and engagement across channels, rather than only counting captured leads. The payoff shows up in cheaper, higher-converting pipeline later.` }] },

  { term: 'Lead Generation', def: `Lead generation is the process of attracting and capturing contact information from potential buyers so they can be nurtured and sold to. It spans inbound tactics like content and forms and outbound tactics like cold outreach. The output is a flow of new leads that feed qualification and the pipeline.`,
    points: [`Attracts and captures contacts to feed the pipeline.`, `Includes inbound (content, forms) and outbound (cold outreach).`, `Output is measured in new leads created per period.`, `Lead quality matters as much as quantity.`],
    why: `Without a steady flow of new leads, the pipeline dries up. Lead generation is the top-line activity that everything downstream, qualification, opportunities, revenue, depends on.`,
    rally: `Rally captures leads from every source into one place, enriches and scores them, and reports conversion by channel so you invest where leads actually close. Rook works new leads instantly to protect conversion.`,
    faqs: [{ q: `What are the main lead generation channels?`, a: `Inbound content and SEO, paid ads, events and webinars, referrals, and outbound prospecting. The best mix depends on your market, deal size, and how buyers research solutions.` }, { q: `Is more leads always better?`, a: `No. A flood of poor-fit leads wastes rep time and inflates vanity metrics. Quality and conversion rate matter more than raw volume, which is why scoring and grading exist.` }] },

  // ---- ICP and market sizing ----
  { term: 'ICP', def: `An ICP, or ideal customer profile, is a description of the type of company that gets the most value from your product and is most profitable to serve. It captures firmographics like industry, size, and region, plus needs and behaviors. The ICP focuses marketing, sales, and product on the right accounts.`,
    points: [`Describes the best-fit company for your product, not a person.`, `Captures industry, size, region, needs, and buying behavior.`, `Focuses go-to-market effort on accounts that will succeed and stay.`, `Different from a buyer persona, which describes an individual.`],
    why: `Selling to everyone means selling to no one well. A sharp ICP concentrates effort on accounts that close faster, spend more, and churn less, raising efficiency across the whole funnel.`,
    rally: `Rally grades every lead and account against your ICP using enriched data, so reps instantly see fit. Rook can prioritize outreach toward in-ICP accounts and flag out-of-ICP deals that will likely disappoint.`,
    faqs: [{ q: `What is the difference between an ICP and a buyer persona?`, a: `An ICP describes the ideal company or account: its industry, size, and traits. A buyer persona describes an individual within that account, such as their role, goals, and pains. You need both.` }, { q: `How do you define your ICP?`, a: `Analyze your best existing customers, those who close fast, pay well, use the product, and stay. Find the firmographic and behavioral traits they share, and target accounts that match.` }] },

  { term: 'Buyer Persona', def: `A buyer persona is a semi-fictional profile of an individual involved in a purchase, capturing their role, goals, challenges, and how they make decisions. Personas help marketing and sales tailor messaging to each stakeholder. Most B2B deals involve several personas, from end user to economic buyer, each with different priorities.`,
    points: [`A profile of an individual buyer, not a company.`, `Captures role, goals, pains, and decision behavior.`, `Deals usually involve multiple personas with different priorities.`, `Guides tailored messaging and content per stakeholder.`],
    why: `A CFO and an end user care about completely different things. Personas let reps speak to each stakeholder's real concerns instead of delivering one generic pitch to everyone.`,
    rally: `Rally can tag each contact on a deal with their persona, and Rook tailors talking points and content to that persona, so the CFO hears about ROI while the operator hears about ease of use.`,
    faqs: [{ q: `How many buyer personas should you have?`, a: `Enough to cover the distinct roles in a typical deal, often three to six in B2B: end user, champion, economic buyer, and sometimes technical or procurement evaluators. Too many personas becomes unmanageable.` }, { q: `How do you build a buyer persona?`, a: `Interview real customers and prospects, review win-loss data, and talk to sales. Capture each role's goals, pains, objections, and where they get information, then keep it updated as the market shifts.` }] },

  { term: 'TAM', def: `TAM, or total addressable market, is the total revenue opportunity available if every possible customer for your product bought it. It sets the outer ceiling of demand and is used to gauge how big a business could become. TAM is the widest of the three market-sizing measures, above SAM and SOM.`,
    points: [`The full revenue opportunity if you captured every possible buyer.`, `The outer ceiling of demand for your category.`, `Used to gauge market size and investment potential.`, `Wider than SAM and SOM, which narrow it to reality.`],
    why: `TAM tells investors and leaders whether a market is big enough to build a large company in. A small TAM caps ambition; a huge TAM signals room to grow for years.`,
    rally: `Rally helps you work TAM downward into reachable accounts by grading your database against ICP fit, so market size turns into a concrete target account list rather than an abstract number.`,
    faqs: [{ q: `How do you calculate TAM?`, a: `Two common ways: top-down, multiplying the total number of potential customers by average revenue per customer; or bottom-up, summing realistic revenue across all segments you could serve. Bottom-up is usually more credible.` }, { q: `What is the difference between TAM, SAM, and SOM?`, a: `TAM is the whole market, SAM is the portion your product and model can actually serve, and SOM is the share you can realistically capture in the near term. Each narrows the one above it.` }] },

  { term: 'SAM', def: `SAM, or serviceable addressable market, is the portion of the total addressable market that your product and business model can actually serve, given constraints like geography, language, regulation, and product fit. It narrows the theoretical TAM to the realistic market you could pursue if you had unlimited sales capacity.`,
    points: [`The share of TAM your product and model can actually serve.`, `Constrained by geography, regulation, language, and fit.`, `More realistic than TAM, still broader than near-term reach.`, `Sits between TAM and SOM in market sizing.`],
    why: `TAM includes buyers you cannot serve today because of region, compliance, or missing features. SAM is the honest market you could go after, which makes it more useful for planning.`,
    rally: `Rally lets you filter your addressable accounts by the traits that define your serviceable market, turning SAM from a slide number into a working list of accounts your team can actually pursue.`,
    faqs: [{ q: `How is SAM different from TAM?`, a: `TAM is the entire market for your category. SAM removes the parts you cannot serve, such as regions you do not sell in or segments your product does not fit, leaving the realistically serviceable market.` }, { q: `Why does SAM matter?`, a: `It sets a credible ceiling for the market you can pursue with your current product and model, which is more useful for strategy and sales planning than the theoretical TAM.` }] },

  { term: 'SOM', def: `SOM, or serviceable obtainable market, is the share of your serviceable addressable market that you can realistically capture in the near term, given your resources, competition, and go-to-market strength. It is the most grounded of the three market-sizing figures and often becomes the basis for revenue targets and plans.`,
    points: [`The slice of SAM you can realistically win near-term.`, `Accounts for competition, resources, and go-to-market reach.`, `The most grounded market-sizing figure of the three.`, `Often used to set revenue targets and quotas.`],
    why: `TAM and SAM describe possibility; SOM describes what you can actually book this year. It is the number that should drive hiring, quota, and pipeline planning.`,
    rally: `Rally connects your SOM to real pipeline by tracking coverage against target accounts, so you can see whether your obtainable market is actually converting into bookings on schedule.`,
    faqs: [{ q: `How do you estimate SOM?`, a: `Start from SAM and apply a realistic capture rate based on your market share, competition, and sales capacity. Bottom-up estimates from actual win rates and coverage tend to be more credible than a flat percentage.` }, { q: `Why is SOM the most important of the three?`, a: `Because it reflects revenue you can actually earn soon. TAM and SAM guide long-term ambition, but SOM is what you plan quotas, hiring, and pipeline around this year.` }] },

  { term: 'Firmographics', def: `Firmographics are the descriptive attributes of a company used to segment and target accounts, such as industry, employee count, annual revenue, location, and growth stage. They are the business-world equivalent of demographics for people. Firmographics power ICP definition, lead grading, territory design, and account targeting in B2B.`,
    points: [`Company-level attributes: industry, size, revenue, location.`, `The B2B equivalent of consumer demographics.`, `Power ICP fit, lead grading, and territory design.`, `Often added automatically through data enrichment.`],
    why: `Firmographics are how you tell a perfect-fit account from a poor one before anyone talks. They drive grading, routing, and targeting so effort goes to accounts that match your ICP.`,
    rally: `Rally enriches leads and accounts with firmographic data on capture, then grades them against your ICP automatically, so reps and routing rules act on complete company profiles from the first touch.`,
    faqs: [{ q: `What are examples of firmographic data?`, a: `Industry or vertical, number of employees, annual revenue, headquarters and office locations, ownership type, growth stage, and number of locations. Together they describe the shape of a target company.` }, { q: `How are firmographics used in sales?`, a: `To define the ideal customer profile, grade and route leads, design sales territories, and prioritize outreach toward accounts that match the traits of your best existing customers.` }] },

  { term: 'Technographics', def: `Technographics describe the technology stack a company uses, such as its CRM, cloud provider, marketing tools, and programming languages. Knowing what a prospect already runs helps sellers judge fit, spot integration opportunities, and time outreach, for example reaching out when a company adopts a complementary or competing tool.`,
    points: [`Data on the tools and technologies a company uses.`, `Reveals fit, integration angles, and competitive displacement.`, `Can trigger timely outreach when a stack changes.`, `Complements firmographics for sharper targeting.`],
    why: `A company running a tool yours integrates with, or a competitor you displace, is a stronger prospect than a random match on size alone. Technographics add that buying-signal layer.`,
    rally: `Rally can enrich accounts with technographic data and factor it into scoring, so reps see which prospects run complementary or competing tools. Rook can prioritize outreach when a relevant technology signal appears.`,
    faqs: [{ q: `What is technographic data used for?`, a: `Targeting accounts by the tools they use, personalizing outreach around integrations or displacements, and prioritizing prospects whose stack signals a strong fit or a buying trigger.` }, { q: `How is technographic data collected?`, a: `Providers detect technologies from website code, job postings, public filings, and other signals. Coverage and accuracy vary, so it is best used as a directional signal rather than gospel.` }] },

  { term: 'Account-Based Marketing', def: `Account-based marketing, or ABM, is a B2B strategy that treats individual high-value accounts as markets of one, coordinating marketing and sales to pursue a defined list of target accounts with personalized campaigns. Instead of casting a wide net for leads, ABM concentrates resources on the specific companies most worth winning.`,
    points: [`Targets a defined list of high-value accounts, not broad leads.`, `Tightly aligns marketing and sales on the same accounts.`, `Uses personalized, multi-channel campaigns per account.`, `Best for high-value, considered, multi-stakeholder deals.`],
    why: `For big deals, chasing volume wastes effort. ABM flips the funnel: pick the accounts worth winning, then surround them with coordinated, personalized effort until they convert.`,
    rally: `Rally aligns marketing and sales on shared target accounts, tracks engagement across the buying committee, and reports account-level pipeline. Rook coordinates personalized outreach across the stakeholders in each account.`,
    faqs: [{ q: `When does account-based marketing make sense?`, a: `When deals are large, complex, and involve multiple stakeholders, so concentrating effort on a few high-value accounts pays off more than chasing broad lead volume. It suits enterprise and strategic selling.` }, { q: `How is ABM different from lead generation?`, a: `Lead gen attracts many contacts and filters for fit. ABM starts by choosing the exact accounts worth winning, then focuses personalized marketing and sales on them. It is depth over breadth.` }] },

  { term: 'Account-Based Selling', def: `Account-based selling, or ABS, is a sales approach that treats a target account as the unit of focus rather than an individual lead, coordinating a team to engage multiple stakeholders across the buying committee. It pairs with account-based marketing and suits complex deals where many people influence the decision.`,
    points: [`The account, not the lead, is the unit of focus.`, `A team engages multiple stakeholders in the buying committee.`, `Pairs closely with account-based marketing.`, `Fits complex, high-value, multi-threaded deals.`],
    why: `Enterprise deals are won across a committee, not with one contact. Account-based selling deliberately multithreads so a single champion leaving cannot sink the deal.`,
    rally: `Rally's deal object holds the full buying committee, so the whole account team sees who is engaged and who is missing. Rook flags single-threaded deals and suggests stakeholders to bring in.`,
    faqs: [{ q: `How is account-based selling different from traditional selling?`, a: `Traditional selling often works one lead or contact at a time. Account-based selling coordinates a team to engage many stakeholders in a target account at once, reducing risk and matching how big deals really get decided.` }, { q: `What roles support account-based selling?`, a: `Typically an account executive leads, supported by SDRs, solution engineers, and sometimes marketing and executives, all coordinated around the same account and buying committee.` }] },

  { term: 'Target Account List', def: `A target account list is a curated set of specific companies that sales and marketing agree to focus on, chosen because they best match the ideal customer profile. It turns market strategy into a concrete list of names, so effort concentrates on accounts worth winning rather than spreading thin across everyone.`,
    points: [`A curated list of best-fit accounts to focus on.`, `Chosen by matching the ideal customer profile.`, `Aligns sales and marketing on the same names.`, `The foundation of account-based strategies.`],
    why: `Strategy is meaningless until it names accounts. A target account list makes ABM actionable and keeps reps from chasing whatever comes in instead of the accounts that matter most.`,
    rally: `Rally builds and grades target account lists from your ICP, tracks engagement and pipeline per account, and keeps sales and marketing working the same names. Rook prioritizes outreach across the list by fit and signal.`,
    faqs: [{ q: `How do you build a target account list?`, a: `Define your ideal customer profile, score your addressable accounts against it, and select the best-fit companies within your capacity to work. Refresh the list as fit data and results come in.` }, { q: `How big should a target account list be?`, a: `Small enough that each account gets real, personalized attention. For strategic ABM a rep might own a few dozen; for scaled programs, a few hundred across a team.` }] },

  { term: 'Named Accounts', def: `Named accounts are specific companies formally assigned to a salesperson or team, who owns all business with those accounts regardless of who inbounds. The named-account model gives reps clear ownership of a defined book, encouraging deep relationships and long-term account development rather than competing over incoming leads.`,
    points: [`Specific accounts assigned to a rep or team by name.`, `The rep owns all business with those accounts.`, `Encourages deep, long-term account development.`, `Common in enterprise and strategic sales.`],
    why: `When ownership is clear, reps invest in relationships rather than fighting over leads. Named accounts reward the patient, multi-year work that big deals and expansions require.`,
    rally: `Rally enforces named-account ownership with routing and RBAC, so leads from an owned account reach the right rep automatically. Rook keeps the account's full history and committee visible to the owner.`,
    faqs: [{ q: `What is the difference between named accounts and territories?`, a: `A territory is usually defined by geography or segment rules; named accounts are a specific list of companies assigned by name. Named accounts give more deliberate control over who owns strategic logos.` }, { q: `Why use a named-account model?`, a: `It gives reps clear ownership and incentive to build deep relationships and expand accounts over time, rather than optimizing for quick wins on whatever leads happen to arrive.` }] },

  // ---- Recurring revenue and retention metrics ----
  { term: 'ARR', def: `ARR, or annual recurring revenue, is the value of a subscription business's recurring revenue normalized to a one-year period. It counts only predictable, contracted subscription revenue, excluding one-time fees. ARR is the headline metric for SaaS companies because it shows the stable revenue base the business can count on each year.`,
    points: [`Annualized value of recurring subscription revenue.`, `Excludes one-time and non-recurring charges.`, `The headline metric for subscription businesses.`, `Equals MRR multiplied by twelve.`],
    why: `ARR is the number investors and boards track because it reflects durable, predictable revenue. Growth in ARR, net of churn, is the clearest measure of a subscription business's health.`,
    rally: `Rally derives ARR from your deal and billing data so the number ties out to signed contracts rather than a spreadsheet guess. Rook can break ARR down by segment, product, and cohort on request.`,
    faqs: [{ q: `How is ARR calculated?`, a: `Sum the annualized value of all active recurring contracts, or multiply monthly recurring revenue by twelve. Exclude one-time fees, services, and usage overages that are not contractually recurring.` }, { q: `What is the difference between ARR and revenue?`, a: `ARR counts only recurring subscription revenue, annualized and forward-looking. Total revenue includes one-time fees, services, and usage, and is recognized as earned. ARR measures the durable base, not everything booked.` }] },

  { term: 'MRR', def: `MRR, or monthly recurring revenue, is the predictable subscription revenue a business earns each month from active customers. It is the monthly counterpart to ARR and is favored by teams that bill or grow month to month. MRR is tracked with its moving parts: new, expansion, contraction, and churned.`,
    points: [`Predictable subscription revenue earned each month.`, `The monthly counterpart to ARR (ARR divided by twelve).`, `Broken into new, expansion, contraction, and churned MRR.`, `Ideal for tracking fast, month-to-month movement.`],
    why: `MRR shows momentum in near real time. Splitting it into new, expansion, contraction, and churn reveals whether growth comes from winning customers or keeping and expanding them.`,
    rally: `Rally computes MRR and its components from live billing and deal data, so you see new, expansion, contraction, and churned movement each month. Rook flags contraction and churn trends before they compound.`,
    faqs: [{ q: `What are the components of MRR?`, a: `New MRR from new customers, expansion MRR from upsells and cross-sells, contraction MRR from downgrades, and churned MRR from cancellations. Net new MRR is the sum of these, positive or negative.` }, { q: `What is the difference between MRR and ARR?`, a: `They measure the same recurring revenue over different periods. MRR is monthly; ARR is annual, roughly MRR times twelve. Monthly-billing businesses favor MRR; annual-contract businesses favor ARR.` }] },

  { term: 'ARPU', def: `ARPU, or average revenue per user, is the average recurring revenue a business earns from each user or customer over a period, calculated by dividing total recurring revenue by the number of users. It reveals monetization efficiency and, tracked over time, shows whether pricing, packaging, and upsells are working.`,
    points: [`Total recurring revenue divided by number of users.`, `Measures how effectively you monetize each customer.`, `Rising ARPU signals successful pricing or upsell.`, `Used to model growth and compare segments.`],
    why: `Growing users is only half the story; ARPU shows whether each customer is worth more over time. Rising ARPU multiplies the value of every new customer you add.`,
    rally: `Rally calculates ARPU from live billing data and breaks it down by plan, segment, and cohort, so you see where monetization is strong or weak. Rook surfaces upsell candidates that would lift ARPU.`,
    faqs: [{ q: `How is ARPU calculated?`, a: `Divide total recurring revenue for a period by the number of active users or accounts in that period. Whether you use users or accounts depends on how you sell and report.` }, { q: `What is the difference between ARPU and ARPA?`, a: `ARPU is revenue per user; ARPA is revenue per account. In B2B, where one account has many users, ARPA is often the more meaningful figure for tracking monetization.` }] },

  { term: 'ARPA', def: `ARPA, or average revenue per account, is the average recurring revenue a business earns per customer account over a period. In B2B, where one account contains many users, ARPA is usually more meaningful than per-user metrics. It is a core input to unit economics, cohort analysis, and revenue forecasting.`,
    points: [`Recurring revenue divided by number of accounts.`, `More meaningful than per-user metrics in B2B.`, `A core input to LTV and unit economics.`, `Segment it to compare account value across tiers.`],
    why: `In B2B you sell to accounts, not individuals, so ARPA reflects real deal economics. Rising ARPA through expansion is one of the most efficient ways to grow revenue.`,
    rally: `Rally reports ARPA by segment and cohort from live billing, and ties it to the deals and expansions that moved it. Rook highlights accounts below their segment's ARPA as expansion opportunities.`,
    faqs: [{ q: `How do you increase ARPA?`, a: `Upsell to higher tiers, cross-sell additional products, reduce discounting, and target higher-value segments. Expansion within existing accounts is usually the most efficient lever.` }, { q: `Is ARPA the same as ACV?`, a: `Not exactly. ARPA is average recurring revenue per account over a period. ACV is the annualized contract value of a specific deal or customer. They are related but measured differently.` }] },

  { term: 'ACV', def: `ACV, or annual contract value, is the average annualized revenue from a single customer contract, excluding one-time fees. For a three-year, 150,000 dollar deal, the ACV is 50,000 dollars. ACV normalizes deals of different lengths to a yearly figure so you can compare them and measure sales productivity.`,
    points: [`Annualized value of a single customer contract.`, `Normalizes multi-year deals to a yearly figure.`, `Excludes one-time setup and services fees.`, `Used to compare deal sizes and set quotas.`],
    why: `Comparing a one-year deal to a three-year deal by total value is misleading. ACV puts them on the same annual footing so you can measure and forecast deal economics fairly.`,
    rally: `Rally computes ACV from each deal's line items and term, so reporting and quotas use a consistent annualized figure. Rook can segment bookings by ACV band to show where your best deals come from.`,
    faqs: [{ q: `How is ACV calculated?`, a: `Divide the total recurring contract value by the number of years in the term, excluding one-time fees. A 24-month, 80,000 dollar recurring deal has an ACV of 40,000 dollars.` }, { q: `What is the difference between ACV and TCV?`, a: `ACV is the annualized value of a contract; TCV is the total value across the entire contract term including one-time fees. TCV is always equal to or larger than annualized ACV times the term.` }] },

  { term: 'TCV', def: `TCV, or total contract value, is the complete value of a customer contract over its entire term, including recurring subscription revenue plus any one-time fees such as setup or professional services. Unlike ACV, which annualizes, TCV captures the full lifetime commitment of a deal, making it useful for cash and backlog planning.`,
    points: [`Total value of a contract across its full term.`, `Includes recurring revenue plus one-time fees.`, `Broader than ACV, which annualizes recurring value.`, `Useful for backlog, cash, and commission planning.`],
    why: `TCV shows the full size of what a customer committed to, which matters for cash forecasting, backlog, and often for how reps are paid on multi-year deals.`,
    rally: `Rally captures TCV from a deal's full line items and term, keeping recurring and one-time components separate so bookings, backlog, and commissions all reconcile. Rook can report TCV alongside ACV on any deal.`,
    faqs: [{ q: `How is TCV calculated?`, a: `Multiply the recurring revenue by the number of periods in the term and add all one-time fees. A three-year deal at 40,000 dollars per year plus a 10,000 dollar setup fee has a TCV of 130,000 dollars.` }, { q: `When should you use TCV instead of ACV?`, a: `Use TCV for cash, backlog, and total-commitment views, and for commissions on full deal value. Use ACV to compare deals of different lengths on an equal annual basis.` }] },

  { term: 'Churn Rate', def: `Churn rate is the percentage of customers or revenue lost over a period. Customer churn counts logos that cancel; revenue churn counts recurring revenue lost. If 100 customers start the month and 5 leave, monthly customer churn is 5 percent. Low churn is essential to sustainable subscription growth.`,
    points: [`Percentage of customers or revenue lost in a period.`, `Measured as customer (logo) churn or revenue churn.`, `High churn quietly undermines even strong new sales.`, `Compounds: small monthly churn adds up over a year.`],
    why: `Churn is the leak in the bucket. A business adding fast but churning faster is running to stand still. Reducing churn is often cheaper than acquiring new customers to replace lost ones.`,
    rally: `Rally tracks churn by cohort, segment, and reason, and health signals flag at-risk accounts before they cancel. Rook can trigger a save play when an account's usage or engagement starts to slide.`,
    faqs: [{ q: `What is the difference between customer churn and revenue churn?`, a: `Customer churn counts the number of accounts lost. Revenue churn counts the recurring revenue lost. A business can lose many small accounts (high logo churn) but little revenue, or vice versa.` }, { q: `What is a good churn rate?`, a: `It varies by market and segment. Enterprise SaaS often targets low single-digit annual churn, while SMB churn runs higher. What matters is that retention plus expansion outpaces losses.` }] },

  { term: 'Revenue Churn', def: `Revenue churn is the percentage of recurring revenue lost over a period from cancellations and downgrades, before counting any expansion. It focuses on dollars rather than customer count, so losing one large account hurts more than losing several small ones. It is a key input to net revenue retention.`,
    points: [`Recurring revenue lost from cancellations and downgrades.`, `Weighted by dollars, so big accounts matter more.`, `Measured before adding expansion revenue (gross).`, `Feeds gross and net revenue retention.`],
    why: `Revenue churn shows the financial impact of losses, which logo churn hides. Losing your biggest customer can be a small logo-churn number but a devastating revenue-churn one.`,
    rally: `Rally computes revenue churn from live billing, separating cancellations from downgrades so you see the cause. Rook flags high-value accounts trending toward contraction so you can intervene before the dollars leave.`,
    faqs: [{ q: `What is the difference between gross and net revenue churn?`, a: `Gross revenue churn counts only revenue lost. Net revenue churn subtracts expansion from existing customers. Net churn can even be negative if expansion outpaces losses, which is a very healthy sign.` }, { q: `Why weight churn by revenue instead of customers?`, a: `Because not all customers are equal. Losing one enterprise account can outweigh losing dozens of small ones. Revenue churn captures the financial reality that logo churn alone misses.` }] },

  { term: 'Logo Churn', def: `Logo churn, also called customer churn, is the percentage of customer accounts (logos) that cancel over a period, regardless of their size. It counts bodies rather than dollars, so a small and a large account each count once. Comparing logo churn to revenue churn shows whether you lose big or small customers.`,
    points: [`Share of customer accounts lost in a period.`, `Counts each account equally, regardless of revenue.`, `Contrast with revenue churn to see which accounts leave.`, `High logo churn can signal onboarding or fit problems.`],
    why: `Logo churn reveals product-market fit and satisfaction breadth. If many customers leave even while revenue holds, something about fit, onboarding, or value delivery is broken.`,
    rally: `Rally tracks logo churn alongside revenue churn and by segment, so you can tell whether losses cluster in a tier or persona. Rook surfaces common traits of churned logos to fix targeting or onboarding.`,
    faqs: [{ q: `Why track logo churn separately from revenue churn?`, a: `Because they tell different stories. Low revenue churn with high logo churn means you keep big accounts but lose small ones, which can signal a fit or onboarding problem in a segment.` }, { q: `How do you reduce logo churn?`, a: `Improve onboarding and time to value, monitor health scores, target better-fit customers, and intervene early when usage drops. Preventing churn is usually far cheaper than replacing lost logos.` }] },

  { term: 'Gross Revenue Retention', def: `Gross revenue retention, or GRR, measures the percentage of recurring revenue retained from existing customers over a period, counting churn and downgrades but not expansion. It is capped at 100 percent and shows how well a business keeps the revenue it already has, independent of any upsell that might mask losses.`,
    points: [`Recurring revenue kept from existing customers, before expansion.`, `Capped at 100 percent by definition.`, `Isolates retention from the masking effect of upsell.`, `A pure measure of how sticky your revenue is.`],
    why: `Expansion can hide a leaky base. GRR strips it away to show the true durability of existing revenue. Strong GRR means the core product delivers lasting value.`,
    rally: `Rally reports GRR by cohort and segment from live billing, separate from expansion, so you see real stickiness. Rook flags declining GRR in a cohort so you can act before it spreads.`,
    faqs: [{ q: `What is the difference between GRR and NRR?`, a: `GRR counts only revenue lost to churn and downgrades and is capped at 100 percent. NRR also adds expansion, so it can exceed 100 percent. GRR shows retention purity; NRR shows net growth from existing customers.` }, { q: `What is a good gross revenue retention rate?`, a: `Strong B2B SaaS often targets 90 percent or higher GRR, meaning less than 10 percent annual revenue lost from the existing base before any expansion. Lower GRR signals a retention problem.` }] },

  { term: 'Net Revenue Retention', def: `Net revenue retention, or NRR, measures the percentage of recurring revenue retained from existing customers over a period, including expansion and after subtracting churn and downgrades. NRR above 100 percent means the existing base grew on its own, a powerful signal because the business would expand even with zero new customers.`,
    points: [`Revenue kept from existing customers, including expansion.`, `Above 100 percent means the base grows without new sales.`, `Combines churn, downgrades, upsell, and cross-sell.`, `A top signal of product value and durable growth.`],
    why: `NRR above 100 percent is the holy grail of subscription economics: your revenue compounds from existing customers alone. Investors prize it because it means efficient, durable growth.`,
    rally: `Rally calculates NRR by cohort from live billing and links every expansion and contraction back to the deals that caused it. Rook surfaces expansion opportunities to push NRR above 100 percent.`,
    faqs: [{ q: `What is a good net revenue retention rate?`, a: `Best-in-class B2B SaaS often exceeds 110 to 120 percent NRR, meaning existing customers spend more each year even after churn. Above 100 percent is the threshold for expansion-driven growth.` }, { q: `How is NRR calculated?`, a: `Take starting recurring revenue from a cohort, add expansion, subtract contraction and churn, then divide by the starting revenue. New-customer revenue is excluded so it measures only the existing base.` }] },

  { term: 'Expansion Revenue', def: `Expansion revenue is additional recurring revenue earned from existing customers through upsells, cross-sells, and usage growth, beyond what they originally paid. It is among the most efficient revenue a business can earn because it requires no new customer acquisition, and it is the engine behind net revenue retention above 100 percent.`,
    points: [`New recurring revenue from existing customers.`, `Comes from upsell, cross-sell, and usage growth.`, `Far cheaper than acquiring new customers.`, `The driver of net revenue retention over 100 percent.`],
    why: `Selling more to happy customers is cheaper and faster than winning new ones. Expansion revenue lowers blended acquisition cost and compounds the value of every account you keep.`,
    rally: `Rally spots expansion signals in usage and account data and tracks expansion deals separately, so you see how much growth comes from the existing base. Rook flags accounts ready to upgrade or add products.`,
    faqs: [{ q: `Why is expansion revenue so valuable?`, a: `It carries little acquisition cost since the customer already exists and trusts you, so its margins are high. It also drives net revenue retention, making growth more efficient and durable.` }, { q: `How do you grow expansion revenue?`, a: `Deliver strong value and adoption, monitor for upgrade signals like hitting limits or adding users, and proactively offer relevant upsells and cross-sells at the right moment in the customer's lifecycle.` }] },

  { term: 'Upsell', def: `An upsell is selling an existing customer a higher-value version of what they already have, such as a premium plan, more seats, or added capacity. It grows account revenue without new acquisition cost and, done well, aligns with the customer getting more value as their needs grow.`,
    points: [`Selling a higher tier or more of the same product.`, `Grows account revenue without new acquisition cost.`, `Best timed to real value or growth signals.`, `A key contributor to expansion revenue and NRR.`],
    why: `Upsell is one of the cheapest forms of growth: no new logo to win, just more value delivered to a customer who already trusts you. Timed to real need, it feels like help, not a pitch.`,
    rally: `Rally watches for upsell triggers like nearing plan limits or adding users, and surfaces them to the account owner. Rook can prepare the upgrade quote in Studio the moment the signal appears.`,
    faqs: [{ q: `What is the difference between upsell and cross-sell?`, a: `Upsell moves a customer to a higher tier or larger quantity of what they already buy. Cross-sell adds a different, complementary product. Both grow account value, but they target different needs.` }, { q: `When is the best time to upsell?`, a: `When the customer is succeeding and bumping against limits, such as running low on seats, capacity, or features. Upselling before the customer has realized value tends to backfire.` }] },

  { term: 'Cross-Sell', def: `A cross-sell is selling an existing customer a different, complementary product or service alongside what they already buy. It broadens the relationship and increases account value, and it often deepens retention because customers using more products are typically stickier and harder for competitors to displace.`,
    points: [`Selling a different, complementary product to a customer.`, `Broadens the relationship beyond the initial purchase.`, `Increases account value and often improves retention.`, `Contributes to expansion revenue and NRR.`],
    why: `Every additional product a customer adopts raises switching costs and account value. Cross-sell turns a single-product customer into a multi-product one who is far harder to lose.`,
    rally: `Rally shows each account's product mix and flags gaps where a complementary product fits, and Rook can recommend the next best product to offer based on similar accounts that expanded.`,
    faqs: [{ q: `How does cross-sell improve retention?`, a: `Customers who rely on multiple products have more invested in your platform and higher switching costs, so they churn less. Cross-selling deepens the relationship as well as growing revenue.` }, { q: `What is the difference between cross-sell and upsell?`, a: `Cross-sell adds a different complementary product; upsell increases the tier or quantity of the existing product. A customer on a base plan buying an add-on module is a cross-sell.` }] },

  { term: 'Contraction', def: `Contraction is a loss of recurring revenue from an existing customer who stays but spends less, through downgrades, dropped seats, or reduced usage. Unlike churn, the customer does not leave entirely. Contraction eats into net revenue retention and often warns that a fuller churn may follow if unaddressed.`,
    points: [`Existing customers reducing spend without fully leaving.`, `Caused by downgrades, seat reductions, or lower usage.`, `Reduces net revenue retention like partial churn.`, `Often an early warning of future full churn.`],
    why: `Contraction is a yellow light. A customer trimming spend is signaling reduced value or budget pressure, and catching it early gives you a chance to re-engage before they leave entirely.`,
    rally: `Rally tracks contraction separately from churn and ties it to the accounts and reasons behind it. Rook flags accounts trending down in seats or usage so success teams can act before the drop deepens.`,
    faqs: [{ q: `What is the difference between contraction and churn?`, a: `Contraction is a partial revenue loss from a customer who remains; churn is the full loss when a customer cancels. Contraction often precedes churn, so it is worth watching as an early signal.` }, { q: `How do you prevent contraction?`, a: `Monitor usage and health, drive adoption of the value the customer bought, and engage proactively when signals dip. Addressing the underlying value gap early is far more effective than reacting at renewal.` }] },

  // ---- Unit economics and SaaS finance ----
  { term: 'CAC', def: `CAC, or customer acquisition cost, is the total sales and marketing spend required to acquire one new customer over a period. It is calculated by dividing all acquisition costs by the number of new customers won. CAC is fundamental to unit economics: a business must earn back CAC through customer revenue to be sustainable.`,
    points: [`Total sales and marketing spend divided by new customers.`, `Includes salaries, ads, tools, and overhead, not just ad spend.`, `Must be recovered through customer revenue to be sustainable.`, `Compared with LTV to judge business viability.`],
    why: `CAC is the price of growth. If it costs more to acquire a customer than that customer is worth, growth destroys value. Watching CAC keeps expansion economically sane.`,
    rally: `Rally ties acquisition spend to closed deals by source, so you see true CAC by channel and segment, not a blended average. Rook highlights which sources produce customers below your target CAC.`,
    faqs: [{ q: `How is CAC calculated?`, a: `Add all sales and marketing costs over a period, including salaries, ads, tools, and overhead, then divide by the number of new customers acquired in that period. Fully loaded CAC gives the truest picture.` }, { q: `What is a good CAC?`, a: `There is no universal number; it depends on customer lifetime value. The common benchmark is an LTV to CAC ratio of at least 3 to 1, and CAC recovered within about twelve months.` }] },

  { term: 'LTV', def: `LTV, or customer lifetime value, is the total recurring revenue or gross profit a business expects to earn from a customer across the entire relationship. It is estimated from average revenue, gross margin, and expected lifetime. LTV sets the ceiling on what you can profitably spend to acquire and retain a customer.`,
    points: [`Total expected value from a customer over their lifetime.`, `Driven by revenue, gross margin, and retention.`, `Sets the ceiling on profitable acquisition spend.`, `Often computed as ARPA times gross margin divided by churn.`],
    why: `LTV tells you how much a customer is truly worth, which bounds what you can spend to win and keep them. Longer retention and higher margin both multiply LTV.`,
    rally: `Rally derives LTV from real revenue, margin, and retention data by segment, so the number reflects actual customer behavior. Rook flags which segments produce the highest-LTV customers to focus acquisition on.`,
    faqs: [{ q: `How is LTV calculated?`, a: `A common formula is average revenue per account times gross margin, divided by the churn rate. This estimates the discounted lifetime gross profit from a typical customer given how long they stay.` }, { q: `Why does retention matter so much to LTV?`, a: `Because LTV divides by churn: halving churn roughly doubles lifetime. Small retention improvements compound into large LTV gains, which is why keeping customers often beats acquiring more.` }] },

  { term: 'LTV:CAC Ratio', def: `The LTV to CAC ratio compares the lifetime value of a customer to the cost of acquiring them. A ratio of 3 to 1 means each customer is worth three times what it cost to win them, a common benchmark for a healthy SaaS business. Too low means unprofitable growth; too high may mean underinvesting.`,
    points: [`Customer lifetime value divided by acquisition cost.`, `A 3 to 1 ratio is the common health benchmark.`, `Below 3 to 1 signals unprofitable or fragile growth.`, `Far above 3 to 1 can mean you are underinvesting in growth.`],
    why: `This single ratio captures whether growth creates or destroys value. It keeps acquisition spend anchored to what customers are actually worth over their lifetime.`,
    rally: `Rally computes LTV and CAC from real revenue and spend data and shows the ratio by segment, so you know which segments to scale and which to fix. Rook flags channels whose ratio is trending below target.`,
    faqs: [{ q: `What is a good LTV to CAC ratio?`, a: `Around 3 to 1 is the widely cited benchmark for healthy SaaS unit economics. Below that suggests acquisition is too expensive; well above it may mean you could grow faster by spending more.` }, { q: `Why can a ratio be too high?`, a: `A very high ratio can mean you are underinvesting in sales and marketing and leaving growth on the table. It signals room to spend more aggressively while still acquiring customers profitably.` }] },

  { term: 'CAC Payback Period', def: `The CAC payback period is the time it takes for the gross profit from a new customer to cover the cost of acquiring them, usually measured in months. A shorter payback means capital is recycled faster into more growth. It is a key efficiency metric, especially for capital-constrained subscription businesses.`,
    points: [`Months for a customer's gross profit to repay acquisition cost.`, `Shorter payback recycles capital into growth faster.`, `Common benchmark is under twelve months.`, `Critical when growth is funded from cash flow.`],
    why: `Payback period governs how fast a business can grow without running out of cash. A 6-month payback funds far more growth per dollar than an 18-month one.`,
    rally: `Rally calculates payback from real CAC, margin, and revenue timing per segment, so you see how fast each channel repays. Rook highlights the segments that recycle cash fastest for prioritized investment.`,
    faqs: [{ q: `How is CAC payback period calculated?`, a: `Divide customer acquisition cost by the monthly gross profit (or monthly recurring revenue times gross margin) that a new customer generates. The result is the number of months to break even on acquisition.` }, { q: `What is a good CAC payback period?`, a: `Under twelve months is a common target for healthy SaaS, and top performers recover CAC in well under a year. Longer paybacks strain cash flow and slow the pace of sustainable growth.` }] },

  { term: 'Rule of 40', def: `The Rule of 40 is a benchmark for software companies stating that revenue growth rate plus profit margin should sum to at least 40 percent. A company growing 30 percent with a 10 percent margin passes. It balances growth against profitability, showing that fast growth can justify thin margins and vice versa.`,
    points: [`Growth rate plus profit margin should total 40 or more.`, `Balances the tradeoff between growth and profitability.`, `A quick health check for software businesses.`, `Margin can be defined several ways, so consistency matters.`],
    why: `The Rule of 40 gives investors one number to judge whether a software company balances growth and efficiency well, rather than buying growth at any cost or starving growth for margin.`,
    rally: `Rally surfaces the growth and margin inputs from live revenue data so leaders can track their Rule of 40 score over time, and Rook can break down which segments help or hurt the balance.`,
    faqs: [{ q: `How is the Rule of 40 calculated?`, a: `Add your revenue growth rate to your profit margin, both as percentages. If the sum is 40 or higher, the company is considered to be balancing growth and profitability well.` }, { q: `Which profit margin should you use?`, a: `Teams use different measures, commonly EBITDA margin or free cash flow margin. The exact choice matters less than applying it consistently so the score is comparable over time.` }] },

  { term: 'Burn Multiple', def: `The burn multiple measures how much a startup burns in cash to generate each dollar of new ARR, calculated as net cash burned divided by net new ARR. A lower multiple means more efficient growth. It is a favored efficiency metric because it captures the full cost of growth in a single figure.`,
    points: [`Net cash burned divided by net new ARR added.`, `Lower is better: less cash burned per dollar of growth.`, `Captures full growth efficiency in one number.`, `Popular for judging capital-efficient startups.`],
    why: `In a tighter funding climate, efficient growth matters more than growth at any cost. The burn multiple exposes how much capital a company consumes to grow, rewarding discipline.`,
    rally: `Rally gives finance clean net new ARR figures tied to real bookings and churn, the numerator's counterpart, so the burn multiple rests on accurate revenue data rather than spreadsheet estimates.`,
    faqs: [{ q: `How is burn multiple calculated?`, a: `Divide net cash burned in a period by the net new ARR added in that period. A company that burned 2 million dollars to add 1 million dollars of net new ARR has a burn multiple of 2.` }, { q: `What is a good burn multiple?`, a: `Lower is better. Under 1 is excellent, 1 to 1.5 is good, and above 2 suggests inefficient growth. The right target depends on stage, since early companies often burn more per dollar of ARR.` }] },

  { term: 'Gross Margin', def: `Gross margin is the percentage of revenue left after subtracting the direct cost of delivering the product or service, known as cost of goods sold. For SaaS this includes hosting, support, and third-party fees. High gross margin, common in software, means most revenue is available to fund growth and profit.`,
    points: [`Revenue minus cost of goods sold, as a percentage.`, `For SaaS, COGS covers hosting, support, and delivery.`, `High gross margin funds growth and profit.`, `A key input to LTV and unit economics.`],
    why: `Gross margin determines how much of each revenue dollar is actually yours to reinvest. Software's high margins are what let SaaS companies spend heavily on growth and still reach profitability.`,
    rally: `Rally keeps recurring revenue and one-time or services revenue separate, which helps finance compute gross margin accurately by revenue type rather than lumping everything together.`,
    faqs: [{ q: `What counts as cost of goods sold in SaaS?`, a: `Typically hosting and infrastructure, customer support and success costs tied to delivery, third-party software fees embedded in the product, and payment processing. It excludes sales, marketing, and R&D.` }, { q: `What is a good SaaS gross margin?`, a: `Healthy software businesses often run 70 to 85 percent gross margin. Lower margins can signal heavy infrastructure or services costs that limit how much revenue is available to fund growth.` }] },

  { term: 'Deferred Revenue', def: `Deferred revenue is money a business has collected from customers for products or services it has not yet delivered. Under accrual accounting it is recorded as a liability, because the company still owes the service. As the service is delivered over time, deferred revenue is gradually recognized as earned revenue.`,
    points: [`Cash collected for undelivered products or services.`, `Recorded as a liability until the service is delivered.`, `Recognized as revenue over the delivery period.`, `Common when customers prepay for annual subscriptions.`],
    why: `Deferred revenue is why a SaaS company can have strong cash and bookings but recognize revenue slowly. Understanding it keeps you from confusing cash collected with revenue earned.`,
    rally: `Rally keeps bookings, billings, and recognized revenue distinct, so finance can see how much collected cash is still deferred against future delivery rather than conflating the three.`,
    faqs: [{ q: `Why is deferred revenue a liability?`, a: `Because the company has been paid but still owes the customer the product or service. Until it delivers, it carries an obligation, so accounting rules treat the prepaid amount as a liability, not revenue.` }, { q: `How does deferred revenue become recognized revenue?`, a: `It is recognized gradually as the service is delivered over the contract term. A prepaid annual subscription moves from deferred revenue to recognized revenue roughly one twelfth each month.` }] },

  { term: 'Recognized Revenue', def: `Recognized revenue is revenue that a business has earned by delivering the product or service, and can therefore record on its income statement under accounting rules. For subscriptions, revenue is recognized ratably over the contract term as the service is provided, not all at once when the customer pays or signs.`,
    points: [`Revenue earned by actually delivering the product or service.`, `Recorded on the income statement under accounting standards.`, `For subscriptions, recognized ratably over the term.`, `Distinct from bookings, billings, and cash collected.`],
    why: `Recognized revenue is the official measure of what a company earned, distinct from what it booked or billed. Confusing the four is a classic way to misread a subscription business's health.`,
    rally: `Rally separates bookings, billings, and recognized revenue so each ties out to its source, giving finance a clean basis for revenue recognition rather than reconstructing it from scattered records.`,
    faqs: [{ q: `What is the difference between recognized revenue and bookings?`, a: `Bookings are the total value committed when a contract is signed. Recognized revenue is earned gradually as the service is delivered. A one-year deal books fully on day one but recognizes over twelve months.` }, { q: `What rules govern revenue recognition?`, a: `Standards such as ASC 606 and IFRS 15 dictate when and how revenue can be recognized, generally as performance obligations are satisfied. This is why subscription revenue is spread across the service period.` }] },

  { term: 'Cohort Analysis', def: `Cohort analysis groups customers by a shared start characteristic, usually the period they signed up, and tracks how each group behaves over time. It reveals retention, expansion, and churn patterns that blended averages hide, showing whether newer cohorts perform better or worse than older ones as the business changes.`,
    points: [`Groups customers by signup period or shared trait.`, `Tracks retention, revenue, and behavior over time per group.`, `Exposes trends that blended averages conceal.`, `Shows whether newer customers behave better than older ones.`],
    why: `Averages hide the truth. Cohort analysis reveals whether a product change improved retention or whether growth is masking a worsening base, which single aggregate numbers cannot show.`,
    rally: `Rally builds cohorts from your live customer data and tracks retention and expansion by cohort automatically, so you can see whether recent changes are improving how customers behave over time.`,
    faqs: [{ q: `Why use cohort analysis instead of averages?`, a: `Averages blend old and new customers and hide trends. Cohorts isolate each group so you can see, for example, whether customers who joined this quarter retain better than last year's, revealing real progress or decline.` }, { q: `What can you learn from cohort analysis?`, a: `Retention curves, payback timing, expansion patterns, and the impact of product or pricing changes. It answers whether the business is getting healthier over time, not just bigger.` }] },

  { term: 'Billings', def: `Billings are the total amount a company has invoiced customers in a period, regardless of when the revenue is recognized. Billings can differ from bookings and revenue because of billing schedules: a customer may commit to a year but be invoiced quarterly. Billings closely track the cash a business will collect.`,
    points: [`Total amount invoiced to customers in a period.`, `Driven by billing schedules, not contract signing.`, `Differs from bookings and recognized revenue.`, `A leading indicator of upcoming cash collection.`],
    why: `Billings sit between bookings and cash. They show what you are actually invoicing now, which helps forecast collections and working capital more accurately than bookings alone.`,
    rally: `Rally links billing schedules to each deal so billings, bookings, and recognized revenue all reconcile. Rook can flag when scheduled billings diverge from expectations, a sign of a billing or collection issue.`,
    faqs: [{ q: `What is the difference between billings and bookings?`, a: `Bookings are the total value a customer commits to when signing. Billings are what you actually invoice, which follows the billing schedule. A one-year deal billed quarterly books fully but bills in four parts.` }, { q: `Why do investors watch billings?`, a: `Billings often lead revenue and cash, so growth in billings can signal future revenue growth before it shows up in recognized revenue. It is a useful forward indicator for subscription businesses.` }] },

  { term: 'Backlog', def: `Backlog is the total value of signed contracts that has not yet been recognized as revenue or billed, representing committed future revenue. It gives visibility into revenue the business has already sold but will earn in future periods. A growing backlog signals strong future revenue; a shrinking one can warn of trouble ahead.`,
    points: [`Signed but not-yet-recognized contract value.`, `Represents committed future revenue.`, `Growing backlog signals healthy future revenue.`, `Common in multi-year and enterprise contracts.`],
    why: `Backlog is money already won but not yet earned. It gives leaders and investors confidence about future revenue and smooths the picture beyond a single quarter's bookings.`,
    rally: `Rally tracks each deal's term and recognized-to-date, so remaining backlog is visible per contract and in aggregate. Rook can report backlog by segment and expected recognition timing on demand.`,
    faqs: [{ q: `What is the difference between backlog and deferred revenue?`, a: `Deferred revenue is cash already collected for undelivered service. Backlog is the value of signed contracts not yet recognized, whether or not it has been billed. Backlog is usually broader than deferred revenue.` }, { q: `Why does backlog matter?`, a: `It shows how much future revenue is already contracted, giving visibility and stability beyond current bookings. Investors read a growing backlog as a sign of durable, predictable future revenue.` }] },

  // ---- Forecasting, quota, and compensation ----
  { term: 'Sales Forecasting', def: `Sales forecasting is the practice of predicting how much revenue a team will close in a future period. It combines pipeline data, deal probabilities, historical win rates, and rep judgment into a projected number that leadership plans the business around. Accurate forecasting drives hiring, spending, and investor commitments.`,
    points: [`Predicts future revenue from pipeline and history.`, `Blends deal data, probabilities, and rep judgment.`, `Drives hiring, budgeting, and board commitments.`, `Accuracy matters more than optimism.`],
    why: `The whole business plans around the forecast. If it is consistently wrong, the company hires, spends, and promises based on revenue that does not arrive, or misses upside it could have captured.`,
    rally: `Rally builds forecasts from live deal data, weighted probabilities, and forecast categories, then compares them to actuals so accuracy improves over time. Rook flags deals whose rep call does not match their real engagement.`,
    faqs: [{ q: `What methods are used for sales forecasting?`, a: `Common approaches include stage-probability weighting, forecast-category roll-ups, historical run rates, and rep commit judgment. Mature teams blend several and compare each against actuals to see which is most reliable.` }, { q: `How do you improve forecast accuracy?`, a: `Enforce consistent stage definitions, ground close dates in real cycle length, weigh deals by real signals not optimism, and track forecast versus actual every period to correct systematic bias.` }] },

  { term: 'Forecast Accuracy', def: `Forecast accuracy measures how close a sales forecast came to actual results, usually as the percentage difference between predicted and realized revenue. High accuracy means leadership can trust the number for planning. Tracking accuracy over time exposes systematic bias, such as reps who always sandbag or always overcommit.`,
    points: [`Measures the gap between forecast and actual revenue.`, `High accuracy makes the forecast a reliable planning tool.`, `Reveals systematic bias by rep, team, or category.`, `Improved by tracking and correcting over many periods.`],
    why: `A forecast is only useful if it is accurate. Measuring accuracy turns forecasting from guesswork into a discipline that gets better each period as bias is identified and corrected.`,
    rally: `Rally records each period's forecast and compares it to actuals by rep and category, so patterns of over- or under-calling become visible. Rook uses that history to adjust confidence on current deals.`,
    faqs: [{ q: `What is a good forecast accuracy?`, a: `Mature teams often aim to land within 5 to 10 percent of forecast. What matters most is consistency and the absence of systematic bias, so leadership can plan confidently around the number.` }, { q: `How do you measure forecast bias?`, a: `Track whether forecasts consistently come in above or below actuals over many periods, and by whom. Reps who always beat their call may sandbag; those who always miss may inflate. Both distort planning.` }] },

  { term: 'Bottom-Up Forecast', def: `A bottom-up forecast builds a revenue projection by summing individual deals or reps' numbers, starting from the granular pipeline and rolling up to a total. Because it is grounded in specific opportunities, it tends to be more accurate and defensible than top-down estimates, though it can miss market shifts the pipeline does not yet reflect.`,
    points: [`Sums individual deals or rep numbers into a total.`, `Grounded in the real, current pipeline.`, `More defensible than a top-down estimate.`, `Can lag broad market shifts the pipeline has not caught.`],
    why: `Bottom-up forecasts are hard to argue with because every dollar traces to a named deal. They anchor planning in reality rather than aspiration or a percentage pulled from the air.`,
    rally: `Rally rolls up bottom-up forecasts automatically from every deal's stage, amount, and category, so the total always reflects the current pipeline. Rook flags the specific deals driving the largest swings.`,
    faqs: [{ q: `What is the difference between bottom-up and top-down forecasting?`, a: `Bottom-up sums specific deals into a total, grounded in the pipeline. Top-down starts from a market or target figure and works down. Bottom-up is usually more accurate; top-down is faster for early planning.` }, { q: `When is bottom-up forecasting best?`, a: `When you have a real pipeline of tracked deals to sum. It is the standard for near-term revenue forecasting because it ties the number to actual opportunities rather than assumptions.` }] },

  { term: 'Top-Down Forecast', def: `A top-down forecast starts from a high-level figure, such as total market size or a corporate revenue target, and works downward to estimate what each segment, region, or rep must produce. It is fast and useful for early planning or new markets without pipeline history, but it is less grounded than bottom-up forecasting.`,
    points: [`Starts from a market or target figure and divides downward.`, `Fast and useful when pipeline data is thin.`, `Good for early-stage or new-market planning.`, `Less grounded than a bottom-up roll-up.`],
    why: `Top-down forecasting lets you set direction before a pipeline exists, useful for new products or markets. It should be reconciled against bottom-up numbers as real deals accumulate.`,
    rally: `Rally lets you set top-down targets and then track bottom-up pipeline against them, so the gap between ambition and reality stays visible. Rook highlights where coverage falls short of the top-down goal.`,
    faqs: [{ q: `When should you use a top-down forecast?`, a: `For early-stage planning, new markets, or new products where there is little pipeline history. It sets a target to work toward, which you refine with bottom-up data as deals accumulate.` }, { q: `What is the risk of top-down forecasting?`, a: `It can be disconnected from reality, setting targets the pipeline cannot support. Always reconcile a top-down number against bottom-up coverage to check whether the goal is achievable.` }] },

  { term: 'Run Rate', def: `Run rate projects current performance forward to estimate future results, typically annualizing a recent period. If a company earned 1 million dollars last month, its annual run rate is 12 million dollars. Run rate is a quick way to express current momentum, though it assumes conditions stay constant and ignores seasonality.`,
    points: [`Annualizes a recent period to project future results.`, `A fast expression of current momentum.`, `Assumes conditions and growth stay constant.`, `Can mislead when there is seasonality or rapid change.`],
    why: `Run rate is a quick shorthand for where a business stands today if nothing changes. It is easy to communicate but should be treated as a snapshot, not a real forecast.`,
    rally: `Rally computes run rate from live revenue data and shows it alongside pipeline-based forecasts, so leaders can compare simple momentum against a grounded, deal-level projection.`,
    faqs: [{ q: `How is run rate calculated?`, a: `Take a recent period's result and extend it over a full year. A month of 500,000 dollars implies a 6 million dollar annual run rate. Quarterly figures are multiplied by four.` }, { q: `What are the limits of run rate?`, a: `It assumes the recent period repeats and ignores seasonality, growth, and one-time events. A strong month driven by a single big deal can overstate the true run rate significantly.` }] },

  { term: 'Quota', def: `A quota is the sales target a rep or team is expected to achieve in a period, usually expressed in revenue or bookings. Quotas translate company goals into individual accountability and are the basis for compensation. A well-set quota is ambitious but attainable, backed by enough pipeline coverage to be realistic.`,
    points: [`The revenue or bookings target for a rep or team.`, `Translates company goals into individual accountability.`, `The basis for commission and comp plans.`, `Should be ambitious yet attainable with adequate coverage.`],
    why: `Quotas focus and motivate the sales team, but only if they are realistic. Quotas set too high demoralize; set too low, they leave revenue on the table. Coverage math keeps them honest.`,
    rally: `Rally tracks attainment against each rep and team quota in real time and checks pipeline coverage against it, so leaders see early whether a quota is on track or at risk. Rook flags coverage gaps.`,
    faqs: [{ q: `How are sales quotas set?`, a: `From the company revenue target divided across the team, adjusted for territory potential, ramp status, and historical performance. Good quota setting balances corporate goals with what each rep can realistically achieve.` }, { q: `What happens if quotas are set too high?`, a: `Consistently unattainable quotas demoralize reps, drive turnover, and make forecasts unreliable as people give up. Quotas should stretch reps while remaining achievable with normal effort and adequate pipeline.` }] },

  { term: 'Quota Attainment', def: `Quota attainment is the percentage of their quota that a rep or team actually achieves in a period. A rep who closes 120,000 dollars against a 100,000 dollar quota has 120 percent attainment. It is the core measure of sales performance and a key input to compensation, coaching, and quota-setting decisions.`,
    points: [`Percentage of quota a rep or team actually achieves.`, `The core measure of individual sales performance.`, `Drives commission payouts and coaching focus.`, `Team attainment distribution reveals quota health.`],
    why: `Attainment shows who is performing and whether quotas are set right. If almost no one hits quota, the targets or the support are broken, not just the reps.`,
    rally: `Rally reports live attainment by rep and team and shows the distribution across the team, so leaders see whether misses are individual or systemic. Rook surfaces the deals that would close an attainment gap.`,
    faqs: [{ q: `What percentage of reps should hit quota?`, a: `A common healthy benchmark is that a majority of reps, often around 60 to 70 percent, attain quota. If far fewer do, quotas may be unrealistic or reps may lack pipeline and support.` }, { q: `How is quota attainment used?`, a: `To calculate commissions, identify top performers and those needing coaching, and calibrate future quotas. Attainment trends across the team also reveal whether targets are set fairly.` }] },

  { term: 'OTE', def: `OTE, or on-target earnings, is the total compensation a salesperson earns if they hit exactly 100 percent of quota. It combines base salary and target commission or bonus, for example a 60,000 dollar base plus 60,000 dollar target variable for a 120,000 dollar OTE. OTE sets clear expectations for pay at plan.`,
    points: [`Total pay at exactly 100 percent of quota.`, `Combines base salary and target variable pay.`, `Often split around 50/50 base to variable in sales.`, `Sets clear expectations for on-plan earnings.`],
    why: `OTE aligns rep expectations and company cost. It tells a rep what to expect for hitting target and lets leadership model sales compensation against the revenue those reps produce.`,
    rally: `Rally can tie attainment to comp plans so reps and managers see progress toward OTE in real time, and Rook can answer where a rep stands against plan without waiting for a spreadsheet reconciliation.`,
    faqs: [{ q: `What is a typical OTE split?`, a: `Many sales roles use a 50/50 split between base salary and target variable pay, though it ranges from 60/40 to 70/30 depending on role and deal complexity. More transactional roles often carry more variable.` }, { q: `Does OTE cap a rep's earnings?`, a: `No. OTE is earnings at 100 percent of quota. Reps who exceed quota typically earn above OTE, often with accelerators that pay a higher rate on over-quota performance.` }] },

  { term: 'Commission', def: `Commission is variable pay a salesperson earns based on the deals they close, usually a percentage of revenue or a rate tied to quota attainment. It is the incentive engine of most sales roles, rewarding results directly. Commission structures range from flat rates to tiered plans with accelerators for over-quota performance.`,
    points: [`Variable pay tied to closed deals or quota attainment.`, `The primary incentive in most sales roles.`, `Structures include flat, tiered, and accelerated rates.`, `Paired with base salary to form total compensation.`],
    why: `Commission aligns rep behavior with company revenue: reps earn more by closing more. Well-designed commission drives the right deals; poorly designed plans encourage gaming or the wrong sales.`,
    rally: `Rally ties closed deals to commission logic so payouts trace to real bookings, and Rook can answer commission questions from the underlying deal data, reducing disputes and shadow spreadsheets.`,
    faqs: [{ q: `What are common commission structures?`, a: `Flat-rate commission pays a fixed percentage of every deal. Tiered plans raise the rate as attainment climbs. Accelerators pay a higher rate above quota. Many plans combine these to reward top performance.` }, { q: `What is a commission accelerator?`, a: `A higher commission rate that kicks in once a rep exceeds quota, rewarding over-performance. For example, deals above 100 percent of quota might pay 1.5 times the normal rate to motivate stretch results.` }] },

  { term: 'Clawback', def: `A clawback is a provision that lets a company reclaim commission already paid to a salesperson if the underlying deal falls through, such as a customer canceling or failing to pay within a set window. Clawbacks protect the business from paying for revenue that never materializes and discourage reps from closing bad-fit deals.`,
    points: [`Recovers paid commission when a deal later fails.`, `Triggered by early cancellation or non-payment.`, `Protects against paying for revenue that never lands.`, `Discourages closing bad-fit or risky deals.`],
    why: `Without clawbacks, a rep could earn commission on a deal that churns immediately, costing the company twice. Clawbacks align incentives toward durable, quality deals rather than quick, fragile ones.`,
    rally: `Rally links commission to deal outcomes and lifecycle, so if a deal cancels within the clawback window the impact is visible and traceable, keeping payouts aligned with revenue that actually stuck.`,
    faqs: [{ q: `When do clawbacks apply?`, a: `Typically when a customer cancels or fails to pay within a defined period after closing, often 90 days to a year. The exact triggers and window are set in the compensation plan.` }, { q: `Why do companies use clawbacks?`, a: `To avoid paying commission on revenue that never materializes and to discourage reps from pushing through deals likely to churn. They align rep incentives with lasting, quality business.` }] },

  { term: 'Draw', def: `A draw is guaranteed pay advanced to a salesperson against their future commissions, ensuring income during ramp or slow periods. A recoverable draw is repaid from later commissions; a non-recoverable draw is not. Draws help new reps survive the ramp before their pipeline produces steady commission income.`,
    points: [`Advance pay against future commissions.`, `Recoverable draws are repaid from later commissions.`, `Non-recoverable draws are effectively a guarantee.`, `Common during a new rep's ramp period.`],
    why: `New reps have no pipeline yet but still need income. A draw bridges the ramp so a company can hire good people who would otherwise not survive months without commission.`,
    rally: `Rally's attainment and commission tracking makes it clear how much a rep has earned against a draw, so both sides can see when commissions have caught up to or exceeded the advanced amount.`,
    faqs: [{ q: `What is the difference between a recoverable and non-recoverable draw?`, a: `A recoverable draw must be paid back from future commissions once the rep earns them. A non-recoverable draw is kept regardless, functioning as a minimum guarantee. Recoverable draws are more common.` }, { q: `Who receives a draw?`, a: `Usually new hires during ramp, reps entering a new territory, or teams in a slow season, to provide income stability before commissions build. It reduces the risk of joining a commission-heavy role.` }] },

  { term: 'SPIFF', def: `A SPIFF is a short-term sales incentive that pays a rep an immediate bonus for a specific action, such as selling a particular product or closing before quarter end. SPIFFs are used to drive focused behavior on top of the regular commission plan, injecting urgency around a priority the business wants to push right now.`,
    points: [`A short-term bonus for a specific sales action.`, `Layered on top of the standard commission plan.`, `Drives focus on a priority product or timeframe.`, `Best used sparingly to keep its motivating power.`],
    why: `SPIFFs let leaders steer effort quickly, toward a new product, a slow quarter-end, or a strategic push, without rewriting the comp plan. Used too often, they lose impact and distort focus.`,
    rally: `Rally can tag deals that qualify for a SPIFF and track progress toward it in real time, so reps see the extra incentive on the exact deals it applies to and leaders measure whether the push worked.`,
    faqs: [{ q: `What does SPIFF stand for?`, a: `It is commonly said to mean Sales Performance Incentive Fund, though usage varies. In practice a SPIFF is simply a short-term bonus for hitting a specific, time-bound sales objective.` }, { q: `When should you use a SPIFF?`, a: `To drive a focused, temporary push: launching a new product, clearing aging inventory, or hitting a quarter-end goal. Overusing them dilutes the effect and can distract reps from core priorities.` }] },

  { term: 'Sales Compensation Plan', def: `A sales compensation plan is the structured framework defining how salespeople are paid, combining base salary, commission, bonuses, quotas, accelerators, and rules like clawbacks. A good plan aligns rep incentives with company goals, is simple enough to understand, and motivates the right behaviors without encouraging gaming or bad deals.`,
    points: [`Defines base, variable pay, quota, and payout rules.`, `Aligns rep incentives with company strategy.`, `Should be simple, fair, and hard to game.`, `Reviewed regularly as goals and markets shift.`],
    why: `Comp plans are the strongest lever on rep behavior. What you pay for is what you get, so a misaligned plan quietly drives the wrong deals no matter what leadership says.`,
    rally: `Rally connects attainment, deals, and payout logic so a comp plan runs on real data instead of spreadsheets, and Rook can answer where any rep stands against plan instantly, cutting disputes.`,
    faqs: [{ q: `What makes a good sales compensation plan?`, a: `Clear alignment with company goals, simplicity a rep can understand and forecast, fair and attainable quotas, and rules that reward quality deals. Overly complex plans confuse reps and invite gaming.` }, { q: `How often should comp plans change?`, a: `Usually reviewed annually, aligned with the fiscal year and strategy. Frequent mid-cycle changes erode trust, so leaders balance keeping the plan current with giving reps stability to sell against it.` }] },

  { term: 'Territory', def: `A sales territory is a defined set of accounts, prospects, or a geographic or market area assigned to a rep or team. Territories divide the market so coverage is organized, reps do not compete for the same accounts, and effort is balanced. They can be based on geography, industry, company size, or named accounts.`,
    points: [`A defined market or account area assigned to a rep.`, `Prevents reps from competing over the same accounts.`, `Based on geography, segment, size, or named accounts.`, `Balanced territories keep opportunity fair across the team.`],
    why: `Clear territories prevent chaos and conflict, and balanced ones give every rep a fair shot at quota. Poorly designed territories create haves and have-nots and distort performance data.`,
    rally: `Rally enforces territory rules through routing and RBAC, so leads and accounts reach the right owner automatically. Rook keeps each territory's pipeline and coverage visible to its owner and manager.`,
    faqs: [{ q: `How are sales territories designed?`, a: `By dividing the market so each rep has balanced opportunity, using geography, industry, company size, or named-account lists. Good design equalizes potential so quota attainment reflects performance, not territory luck.` }, { q: `Why do balanced territories matter?`, a: `Unbalanced territories mean some reps have far more opportunity than others, distorting attainment and morale. Balancing potential across territories makes quotas fair and performance comparisons meaningful.` }] },

  { term: 'Capacity Planning', def: `Sales capacity planning estimates how many reps, ramped and productive, a company needs to hit its revenue target, accounting for quota, ramp time, and expected attrition. It connects the revenue goal to a concrete hiring plan, ensuring the team is large and ready enough to produce the number leadership has committed to.`,
    points: [`Estimates the headcount needed to hit a revenue target.`, `Accounts for quota, ramp time, and attrition.`, `Turns a revenue goal into a hiring plan.`, `Prevents missing targets from being understaffed.`],
    why: `A revenue goal is unreachable without enough ramped reps to produce it. Capacity planning ensures hiring happens early enough, given ramp time, that the team can actually deliver the number.`,
    rally: `Rally's real attainment, ramp, and productivity data feed capacity planning with accurate inputs, so headcount plans rest on how reps actually perform rather than optimistic assumptions.`,
    faqs: [{ q: `What inputs does capacity planning need?`, a: `The revenue target, average productive quota per rep, ramp time for new hires, expected attrition, and current headcount. Together these reveal how many reps to hire and when to hit the goal.` }, { q: `Why account for ramp time in capacity planning?`, a: `Because new reps do not produce full quota immediately. If you ignore ramp, you hire too late and miss the number even with the right final headcount. Ramp dictates how early to hire.` }] },

  // ---- Sales process and activities ----
  { term: 'Prospecting', def: `Prospecting is the work of identifying and reaching out to potential customers to create new sales opportunities. It includes researching target accounts, finding the right contacts, and making first contact through calls, emails, and social touches. Consistent prospecting is what keeps a rep's pipeline full and future quota achievable.`,
    points: [`Finding and contacting potential customers.`, `Includes research, list-building, and first outreach.`, `Fills the top of the pipeline with new opportunities.`, `Consistency matters more than intensity.`],
    why: `Prospecting is the least urgent but most important sales activity: neglect it and the pipeline dries up two quarters later. Reps who prospect steadily rarely face a revenue cliff.`,
    rally: `Rally surfaces best-fit accounts, enriches contacts, and runs outbound sequences, so prospecting is targeted rather than random. Rook drafts personalized first touches and works the sequence so reps stay consistent.`,
    faqs: [{ q: `What is the difference between prospecting and lead generation?`, a: `Lead generation often refers to marketing attracting inbound interest at scale. Prospecting is the rep-driven work of proactively finding and contacting specific potential buyers. They overlap but prospecting is usually more individual and outbound.` }, { q: `How much time should reps spend prospecting?`, a: `Enough to maintain pipeline coverage consistently, which for many reps means a set block of time daily. Sporadic prospecting creates feast-and-famine cycles, so regular effort beats occasional bursts.` }] },

  { term: 'Cold Calling', def: `Cold calling is contacting a prospect by phone who has had no prior relationship or expressed interest, to start a sales conversation. Despite predictions of its death, targeted cold calling still works in B2B, especially paired with research and other touches. It demands a strong opener, resilience, and persistence.`,
    points: [`Phoning prospects with no prior relationship.`, `Still effective in B2B when targeted and researched.`, `Works best combined with email and social touches.`, `Requires a strong opener and resilience.`],
    why: `Cold calling remains one of the few ways to reach a decision maker directly and get a real-time conversation. Combined with other channels, it breaks through where email alone stalls.`,
    rally: `Rally sequences calls alongside email and social touches and logs every attempt automatically, so reps know exactly who to call next and what was said. Rook preps the account context before each call.`,
    faqs: [{ q: `Does cold calling still work?`, a: `Yes, when targeted and researched. Connect rates are lower than they once were, but a well-timed call to a good-fit prospect, coordinated with email and social, still books meetings that email alone would not.` }, { q: `How do you improve cold call success?`, a: `Research the prospect first, lead with a relevant reason for calling, keep the opener short, ask questions rather than pitch, and combine calls with email and social touches in a coordinated sequence.` }] },

  { term: 'Cold Email', def: `A cold email is an unsolicited message sent to a prospect with no prior relationship, aiming to start a sales conversation. Effective cold emails are short, personalized, and focused on the prospect's problem rather than the product. They must also comply with anti-spam laws and respect the recipient's time to earn a reply.`,
    points: [`An unsolicited first-touch email to a prospect.`, `Short, personalized, and problem-focused wins replies.`, `Must comply with anti-spam regulations.`, `Best used within a multi-touch sequence.`],
    why: `Cold email scales outbound in a way calling cannot, reaching many targeted prospects efficiently. But relevance is everything: generic blasts get ignored or marked as spam.`,
    rally: `Rally personalizes cold emails using enriched account data and runs them in sequences with calls and social touches. Rook drafts tailored first lines and manages follow-ups so outreach stays relevant at scale.`,
    faqs: [{ q: `What makes a good cold email?`, a: `Brevity, genuine personalization tied to the prospect's situation, a clear and low-friction ask, and a focus on their problem over your product. Long, generic, product-heavy emails rarely get replies.` }, { q: `Is cold emailing legal?`, a: `It can be, but it is regulated. Laws like CAN-SPAM in the US and GDPR in Europe set rules on consent, identification, and opt-out. Compliance and respect for the recipient are essential.` }] },

  { term: 'Cold Outreach', def: `Cold outreach is any first contact with a prospect who has not expressed interest, across channels like email, phone, and social media. It is the engine of outbound sales, letting teams reach specific target accounts proactively. Effective cold outreach is coordinated across channels, personalized, and persistent without becoming a nuisance.`,
    points: [`First contact across email, phone, and social.`, `The core engine of outbound sales.`, `Best coordinated across channels, not single-touch.`, `Personalization and persistence drive results.`],
    why: `Cold outreach lets you go after exactly the accounts you want instead of waiting for inbound. A coordinated multi-channel approach dramatically outperforms any single channel used alone.`,
    rally: `Rally orchestrates cold outreach across email, calls, and social in one sequence per prospect, and Rook personalizes each touch and manages timing so reps run more targeted outreach with less manual effort.`,
    faqs: [{ q: `How many touches does cold outreach take?`, a: `Most prospects need multiple touches across channels before responding, often six or more spread over weeks. A single email rarely works; persistence coordinated across email, phone, and social is what breaks through.` }, { q: `How do you avoid annoying prospects with cold outreach?`, a: `Target well so your message is relevant, personalize genuinely, space touches sensibly, offer real value, and respect opt-outs. Relevance and restraint separate effective outreach from spam.` }] },

  { term: 'Discovery Call', def: `A discovery call is an early sales conversation focused on understanding a prospect's situation, challenges, goals, and buying process, rather than pitching. The rep asks questions and listens to qualify the deal and tailor the solution. A strong discovery call sets the foundation for every later stage and often decides whether a deal is real.`,
    points: [`An early call to understand the buyer, not pitch.`, `Uncovers challenges, goals, and the buying process.`, `Qualifies the deal and shapes the tailored solution.`, `The most important call in most sales cycles.`],
    why: `Deals are won or lost in discovery. A rep who deeply understands the buyer's problem can tailor everything that follows; one who rushes to pitch sells blind and loses to those who listened.`,
    rally: `Rally captures discovery notes structured against your qualification framework, and Rook can summarize a recorded discovery call into pain, metrics, stakeholders, and next steps so nothing is lost.`,
    faqs: [{ q: `What should you cover in a discovery call?`, a: `The prospect's current situation and challenges, the impact and urgency of the problem, their goals, who is involved in the decision, their process and timeline, and how they will measure success.` }, { q: `How long should a discovery call be?`, a: `Often 30 to 45 minutes, enough to explore the problem without exhausting the prospect. What matters is spending most of it listening and asking questions rather than presenting.` }] },

  { term: 'Demo', def: `A demo, or product demonstration, is a sales presentation that shows a prospect how a product works and solves their specific problems. An effective demo is tailored to what discovery uncovered, focusing on the buyer's use cases rather than every feature. Done well, it moves a qualified prospect from interest to serious evaluation.`,
    points: [`Shows how the product solves the buyer's problems.`, `Best tailored to discovery findings, not feature-complete.`, `Moves qualified prospects toward evaluation.`, `Should invite interaction, not be a one-way pitch.`],
    why: `A generic feature tour bores buyers; a tailored demo that solves their exact problem sells. The best demos make the prospect picture their own success with the product.`,
    rally: `Rally being alive with data means demos show a realistic, populated product, not empty screens. Rook can prep a demo script from the deal's discovery notes so reps focus on the buyer's actual use cases.`,
    faqs: [{ q: `What makes a good product demo?`, a: `Tailoring it to the buyer's specific challenges from discovery, leading with their top use cases, keeping it interactive, and confirming value as you go. Showing every feature dilutes the message and loses attention.` }, { q: `When in the sales cycle should you demo?`, a: `After discovery, once you understand the buyer's problems well enough to tailor the demo. Demoing too early, before qualification, wastes effort and produces a generic pitch that rarely resonates.` }] },

  { term: 'Proof of Concept', def: `A proof of concept, or POC, is a limited, hands-on trial where a prospect tests whether a product works for their specific use case before committing. Common in complex or technical sales, a POC de-risks the purchase by letting the buyer validate value with their own data and requirements, usually against agreed success criteria.`,
    points: [`A limited trial validating the product for a use case.`, `Common in complex and technical B2B sales.`, `Should have agreed, written success criteria.`, `De-risks the purchase for the buyer.`],
    why: `Big or technical purchases carry real risk, and buyers want proof, not promises. A POC with clear success criteria lets them validate value, which builds the confidence to sign.`,
    rally: `Rally being usable and populated on day one lowers the friction of a POC, and Rook can track POC milestones and success criteria on the deal so both sides stay aligned on what proves value.`,
    faqs: [{ q: `How do you run a successful proof of concept?`, a: `Define clear, written success criteria up front, scope it tightly to the buyer's key use case, set a timeline, support the buyer through it, and agree what happens when the criteria are met.` }, { q: `What is the risk of a poorly scoped POC?`, a: `Without agreed success criteria, a POC can drag on indefinitely as goalposts move, consuming resources without leading to a decision. Clear scope and criteria keep it a step toward closing, not free consulting.` }] },

  { term: 'Sales Cadence', def: `A sales cadence is a structured, timed sequence of outreach touches a rep follows to engage a prospect, specifying the channels, messages, and intervals. For example, a cadence might mix emails, calls, and social touches over two weeks. Cadences bring consistency and persistence to outreach so no prospect is contacted too little or too much.`,
    points: [`A timed sequence of outreach touches across channels.`, `Specifies channel, message, and interval for each step.`, `Ensures consistent, persistent follow-up.`, `Often 8 to 12 touches over a few weeks.`],
    why: `Most deals require many touches, and reps left to improvise give up too soon or nag inconsistently. A cadence encodes the right rhythm so persistence is systematic, not accidental.`,
    rally: `Rally runs cadences across email, phone, and social with the timing built in, and Rook executes the touches and adapts them to responses, so reps follow a proven rhythm without manual tracking.`,
    faqs: [{ q: `What is the difference between a cadence and a sequence?`, a: `The terms are largely interchangeable. Both describe a structured series of timed outreach touches. Some teams use cadence for the overall rhythm and sequence for the specific automated steps in a tool.` }, { q: `How long should a sales cadence be?`, a: `Commonly 8 to 12 touches over two to four weeks, mixing channels. The right length depends on your market and deal size, but stopping after one or two touches leaves most responses unearned.` }] },

  { term: 'Sales Sequence', def: `A sales sequence is an automated series of outreach steps, such as emails, calls, and social touches, delivered to a prospect on a set schedule. Sequences ensure consistent follow-up at scale, freeing reps from remembering every touch. The best sequences are personalized and adapt based on whether and how the prospect responds.`,
    points: [`An automated, scheduled series of outreach steps.`, `Delivers consistent follow-up at scale.`, `Combines email, calls, and social touches.`, `Best when personalized and response-aware.`],
    why: `Manual follow-up breaks down as prospect volume grows. Sequences automate the discipline so every prospect gets the full set of touches, which lifts response rates without adding rep workload.`,
    rally: `Rally runs multi-step, multi-channel sequences and Rook personalizes each message and adjusts the path based on replies, so outreach stays relevant and consistent even across hundreds of prospects.`,
    faqs: [{ q: `How is a sequence different from a drip campaign?`, a: `A sequence is often sales-driven, multi-channel, and pauses when a prospect replies, aiming for a conversation. A drip campaign is usually marketing email only, sent on a schedule to nurture over time.` }, { q: `Should sequences be automated or manual?`, a: `A blend works best: automate scheduling and reminders for consistency, but keep personalization and human judgment in the loop. Fully generic automated sequences underperform ones with genuine personalization.` }] },

  { term: 'Drip Campaign', def: `A drip campaign is a series of automated marketing messages, usually emails, sent to prospects or customers on a schedule or triggered by behavior. Each message drips out over time to nurture the relationship, educate, and move recipients toward a purchase. Drips keep your brand present without requiring manual sending.`,
    points: [`Automated messages sent on a schedule or by trigger.`, `Nurtures and educates recipients over time.`, `Usually email-based and marketing-driven.`, `Keeps the brand present through long consideration.`],
    why: `Most prospects are not ready to buy immediately. Drip campaigns nurture them automatically over weeks or months so they stay engaged until they are ready, capturing demand that would otherwise be lost.`,
    rally: `Rally runs behavior-triggered drips and tracks engagement, moving a prospect back to sales when they heat up. Rook can tailor drip content to a recipient's interests and lifecycle stage.`,
    faqs: [{ q: `What triggers a drip campaign?`, a: `Either a schedule after an entry event like signing up, or behaviors such as downloading content, visiting pricing, or abandoning a trial. Behavior-triggered drips tend to be more relevant and effective.` }, { q: `How is a drip campaign different from a newsletter?`, a: `A drip is a predefined sequence each recipient moves through from their own start point. A newsletter is a single broadcast sent to everyone at once. Drips are personalized in timing; newsletters are not.` }] },

  { term: 'Sales Enablement', def: `Sales enablement is the practice of equipping salespeople with the content, training, tools, and information they need to sell effectively. It spans onboarding, playbooks, battlecards, product training, and the systems that deliver them. Good enablement shortens ramp, raises win rates, and keeps messaging consistent across the whole team.`,
    points: [`Equips reps with content, training, and tools to sell.`, `Includes onboarding, playbooks, and battlecards.`, `Shortens ramp and lifts win rates.`, `Keeps messaging consistent across the team.`],
    why: `Even great reps underperform without the right materials and knowledge at hand. Enablement multiplies the team's effectiveness by making best practices and content available at the moment of need.`,
    rally: `Rally surfaces the right playbook, battlecard, or content on the deal when a rep needs it, and Rook can answer product and objection questions in context, so enablement lives where selling happens.`,
    faqs: [{ q: `What does sales enablement include?`, a: `Onboarding and training, sales playbooks, battlecards, case studies and content, product and competitive knowledge, and the tools and analytics that deliver them. It also covers coaching and process improvement.` }, { q: `How do you measure sales enablement?`, a: `Through ramp time, win rate, quota attainment, content usage, and deal velocity. Effective enablement shows up as faster-productive reps, more consistent messaging, and higher conversion across the team.` }] },

  { term: 'Sales Playbook', def: `A sales playbook is a documented guide that captures a team's proven approach to selling, including the ideal customer profile, sales process, messaging, objection responses, and best practices for each stage. It codifies what top reps do so the whole team can replicate it, bringing consistency and faster ramp to the sales organization.`,
    points: [`Documents the team's proven selling approach.`, `Covers process, messaging, and objection handling by stage.`, `Codifies what top performers do for everyone.`, `Speeds ramp and improves consistency.`],
    why: `A playbook turns the tacit knowledge of top reps into a shared asset. It shortens ramp, raises the floor of team performance, and keeps everyone selling a consistent, tested way.`,
    rally: `Rally surfaces the relevant playbook step on the deal based on its stage, and Rook can prompt the right next action or message from the playbook in context, so it guides selling instead of sitting in a document.`,
    faqs: [{ q: `What goes into a sales playbook?`, a: `The ideal customer profile, buyer personas, the sales process and stage criteria, discovery questions, messaging and value propositions, objection responses, competitive battlecards, and best practices for each stage of the cycle.` }, { q: `How do you keep a playbook useful?`, a: `Update it with what actually works, surface it in the flow of selling rather than a static file, and tie it to real deal data. A playbook nobody references is just documentation.` }] },

  { term: 'Battlecard', def: `A battlecard is a concise reference that helps reps sell against a specific competitor, summarizing that rival's strengths, weaknesses, pricing, and the best positioning and objection responses to use. Battlecards give reps quick, confident answers when a prospect raises a competitor, turning competitive situations from a stumble into a strength.`,
    points: [`A quick reference for selling against a competitor.`, `Summarizes rival strengths, weaknesses, and positioning.`, `Includes objection responses and trap-setting questions.`, `Keeps reps confident in competitive deals.`],
    why: `Competitive deals are often decided by how well a rep handles the comparison. A battlecard arms them with tested positioning so they respond with confidence instead of scrambling.`,
    rally: `Rally can attach the right battlecard to a deal when a competitor is tagged, and Rook can surface the relevant counter-positioning in context, so reps get competitive guidance exactly when they need it.`,
    faqs: [{ q: `What should a battlecard contain?`, a: `A competitor's key strengths and weaknesses, how your product compares, pricing differences, common objections and responses, questions that expose the competitor's gaps, and proof points like customer wins.` }, { q: `How do you keep battlecards current?`, a: `Update them from real win-loss data and field feedback as competitors change pricing, features, and messaging. Stale battlecards mislead reps, so treat them as living documents tied to actual competitive outcomes.` }] },

  { term: 'Objection Handling', def: `Objection handling is the skill of responding to a prospect's concerns or hesitations, about price, timing, fit, or competitors, in a way that addresses the real issue and keeps the deal moving. Good objection handling listens first to understand the concern, then responds with evidence and empathy rather than defensiveness.`,
    points: [`Responding to buyer concerns to keep deals moving.`, `Common objections: price, timing, fit, competition.`, `Listen to understand before responding.`, `Address the real concern, not just the stated words.`],
    why: `Objections are normal and often signal genuine interest. Handling them well turns hesitation into commitment; handling them poorly, with defensiveness or scripts, loses deals that were nearly won.`,
    rally: `Rally can surface tested responses to common objections from your playbook on the deal, and Rook can recall how similar objections were resolved in past won deals, so reps respond with proven answers.`,
    faqs: [{ q: `What is the best way to handle an objection?`, a: `Listen fully, acknowledge the concern, ask questions to understand what is really behind it, then respond with relevant evidence and empathy. Resolving the underlying issue matters more than winning the argument.` }, { q: `Are objections a bad sign?`, a: `Usually not. Objections often mean the prospect is seriously considering buying and needs a concern resolved. Silence and disengagement are worse signs than clear, engaged objections.` }] },

  { term: 'Value Proposition', def: `A value proposition is a clear statement of the benefit a customer gets from a product, why it matters to them, and how it is better than alternatives. It answers the buyer's core question of why they should choose you. A strong value proposition is specific, outcome-focused, and framed around the customer's problem.`,
    points: [`States the benefit, its importance, and the differentiation.`, `Answers why the buyer should choose you.`, `Focused on customer outcomes, not features.`, `Should be specific and differentiated.`],
    why: `Buyers are flooded with options. A sharp value proposition cuts through by making the payoff obvious and specific, while a vague one leaves the prospect unsure why you are worth their time.`,
    rally: `Rally can store tailored value propositions by persona and use case, and Rook can assemble the right one for a specific stakeholder based on the deal's context, so messaging lands for each buyer.`,
    faqs: [{ q: `What makes a strong value proposition?`, a: `Specificity, a focus on the customer's outcome rather than your features, and clear differentiation from alternatives. It should be understandable in seconds and grounded in the buyer's real problem.` }, { q: `How is a value proposition different from a slogan?`, a: `A slogan is a catchy brand phrase. A value proposition is a substantive statement of the concrete benefit and differentiation a customer receives. The value proposition informs strategy; the slogan is marketing dressing.` }] },

  { term: 'Buying Signal', def: `A buying signal is any action or statement from a prospect that indicates increased interest or readiness to purchase, such as requesting pricing, visiting the pricing page repeatedly, asking about implementation, or looping in a decision maker. Recognizing buying signals lets reps time their outreach and advance deals at the right moment.`,
    points: [`An action signaling increased purchase interest.`, `Examples: pricing requests, repeat visits, adding stakeholders.`, `Guides the timing of rep outreach.`, `Can be behavioral, verbal, or contextual.`],
    why: `Reaching out at the moment interest spikes converts far better than random timing. Buying signals tell reps when a prospect is leaning in, so they engage while intent is highest.`,
    rally: `Rally detects buying signals across engagement and product usage and surfaces them to the deal owner, and Rook can trigger timely outreach the moment a strong signal appears, so hot moments are not missed.`,
    faqs: [{ q: `What are common buying signals?`, a: `Requesting pricing or a proposal, repeated visits to pricing or product pages, asking about implementation or contracts, involving new stakeholders, and questions about timelines. Together they indicate rising intent.` }, { q: `How should reps respond to buying signals?`, a: `Act quickly while interest is high: reach out with relevant next steps, offer the information the signal implies they want, and work to advance the deal. Speed and relevance capitalize on the moment.` }] },

  { term: 'Intent Data', def: `Intent data is information about the online behavior of prospects that signals they may be researching a purchase, such as reading topic-related content, comparing vendors, or spiking activity around certain keywords. It helps teams identify accounts that are actively in-market and prioritize outreach to buyers who are already looking.`,
    points: [`Behavioral data signaling active purchase research.`, `Comes from first-party and third-party sources.`, `Identifies accounts currently in-market.`, `Sharpens outreach timing and prioritization.`],
    why: `Reaching accounts already researching your category converts far better than cold prospecting. Intent data points reps toward buyers who are actively looking, right when timing matters most.`,
    rally: `Rally can ingest intent signals and factor them into account scoring and prioritization, and Rook can trigger outreach to accounts showing a surge of relevant intent, so reps focus on in-market buyers.`,
    faqs: [{ q: `What is the difference between first-party and third-party intent data?`, a: `First-party intent comes from behavior on your own properties, like site visits and content downloads. Third-party intent comes from providers tracking research activity across the web. Both indicate interest; first-party is usually stronger.` }, { q: `How is intent data used?`, a: `To identify accounts actively researching your category, prioritize them for outreach, time messages to their interest, and focus marketing and sales on buyers already in-market rather than cold targets.` }] },

  { term: 'Social Selling', def: `Social selling is the practice of using social media, especially professional networks, to research prospects, build relationships, share relevant content, and engage buyers before and during the sales process. Rather than cold pitching, reps establish credibility and rapport through helpful interaction, warming prospects so outreach lands better and trust builds earlier.`,
    points: [`Using social networks to research and engage buyers.`, `Builds credibility and rapport before pitching.`, `Complements outbound rather than replacing it.`, `Works through helpful content and genuine interaction.`],
    why: `Buyers research and form opinions on social platforms long before talking to sales. A rep who is visible, credible, and helpful there earns trust and warm conversations that cold outreach cannot.`,
    rally: `Rally sequences social touches alongside email and calls and logs them on the deal, so social engagement is part of the coordinated outreach. Rook can suggest relevant moments to engage a prospect socially.`,
    faqs: [{ q: `Does social selling actually work?`, a: `Yes, when done authentically. Reps who build a credible presence and engage helpfully see warmer responses and more inbound interest. It works best as part of a broader outreach approach, not a standalone tactic.` }, { q: `What does social selling involve?`, a: `Optimizing your professional profile, sharing and commenting on relevant content, researching prospects, engaging with their posts, and building relationships over time, so outreach comes from a place of familiarity and credibility.` }] },

  { term: 'Multithreading', def: `Multithreading is the practice of building relationships with several stakeholders within a target account rather than relying on a single contact. Because complex B2B deals involve a buying committee, engaging multiple people reduces risk: if one champion leaves or loses influence, the deal survives. Multithreaded deals close more often and more predictably.`,
    points: [`Engaging multiple stakeholders in one account.`, `Reduces risk of a single point of failure.`, `Matches how committees actually decide.`, `Multithreaded deals close at higher rates.`],
    why: `Single-threaded deals are fragile: if your one contact goes quiet or leaves, the deal dies. Multithreading spreads relationships across the committee so the deal does not depend on any one person.`,
    rally: `Rally's deal object holds the full buying committee, so it is obvious who is engaged and who is missing. Rook flags single-threaded deals and suggests which stakeholders to bring in to de-risk them.`,
    faqs: [{ q: `Why is multithreading important?`, a: `Complex deals are decided by a committee, and relying on one contact is risky. If that person leaves or loses influence, a single-threaded deal collapses. Multithreading keeps the deal alive across multiple relationships.` }, { q: `How do you multithread a deal?`, a: `Map the buying committee, then use your champion, referrals, and outreach to build relationships with other stakeholders like the economic buyer, technical evaluators, and end users, each with messaging relevant to their role.` }] },

  // ---- Buying roles and deal structure ----
  { term: 'Champion', def: `A champion is an internal advocate at a prospect account who wants your solution to win and actively promotes it inside their organization. Champions have influence and access, sell on your behalf when you are not in the room, and guide you through the buying process. Developing a strong champion is often decisive in complex deals.`,
    points: [`An internal advocate who promotes your solution.`, `Has influence and access within the account.`, `Sells for you when you are not present.`, `Often the difference-maker in complex deals.`],
    why: `You cannot be in every internal meeting, but a champion can. A strong champion carries your case through the buying process and to the people you never meet, which is often what wins the deal.`,
    rally: `Rally tracks champions on the deal's buying committee and Rook flags when a deal lacks an identified champion or when your champion goes quiet, so you can strengthen or replace that advocacy before it costs you.`,
    faqs: [{ q: `How do you identify a real champion?`, a: `A true champion has influence, gives you access and information, and takes action on your behalf, not just friendly conversations. Test it by asking them to do something, like arrange a meeting with the economic buyer.` }, { q: `What if you do not have a champion?`, a: `Work to develop one by finding the person who gains most from your solution and equipping them to advocate internally. Deals without a champion often stall because no one pushes them forward inside the account.` }] },

  { term: 'Buying Committee', def: `A buying committee is the group of people within an organization who together influence or decide a purchase. In B2B it commonly includes end users, a champion, technical evaluators, an economic buyer, and procurement. Modern complex deals often involve six to ten people, so understanding and engaging the whole committee is essential to winning.`,
    points: [`The group that collectively decides a purchase.`, `Includes users, champion, evaluators, economic buyer, procurement.`, `Often six to ten people in complex B2B deals.`, `Each member has different priorities and concerns.`],
    why: `Deals are won across a committee, not with one contact. Mapping and engaging every member, each with messaging for their concerns, is what separates predictable wins from single-threaded gambles.`,
    rally: `Rally's deal object holds the entire buying committee with roles and engagement, so the team sees who matters and who is covered. Rook flags missing stakeholders and tailors messaging per committee member.`,
    faqs: [{ q: `Who is on a typical buying committee?`, a: `Commonly end users who will use the product, a champion advocating internally, technical or security evaluators, an economic buyer who controls budget, and procurement or legal. Larger deals add more roles and influencers.` }, { q: `How do you sell to a buying committee?`, a: `Map every member and their priorities, multithread to build relationships across them, and tailor messaging to each role. A mutual action plan aligns the whole committee on the path to a decision.` }] },

  { term: 'Economic Buyer', def: `The economic buyer is the person with the authority and budget to approve a purchase, who can say yes when others can only say no. They care most about business outcomes and return on investment. Reaching and convincing the economic buyer is essential, because a deal cannot truly close without their approval.`,
    points: [`The person with authority and budget to approve the deal.`, `Can grant final approval that others cannot.`, `Focused on business outcomes and ROI.`, `Access to them is a key qualification signal.`],
    why: `Many deals stall because reps sell to enthusiastic users without ever reaching the person who controls the money. Confirming access to the economic buyer is one of the strongest signs a deal is real.`,
    rally: `Rally captures the economic buyer on the deal and Rook flags opportunities advancing without one identified or engaged, a classic reason deals slip. It helps reps confirm access before forecasting a deal.`,
    faqs: [{ q: `How is the economic buyer different from a decision maker?`, a: `The economic buyer specifically controls budget and can approve spend. Decision maker is a broader term; a technical or user decision maker may choose the product but still need the economic buyer to fund it.` }, { q: `Why is reaching the economic buyer so important?`, a: `Because no deal truly closes without their approval. Selling only to users and champions leaves the deal exposed; the economic buyer weighs ROI and holds the budget, so their buy-in is decisive.` }] },

  { term: 'Decision Maker', def: `A decision maker is a person with the authority to make or heavily influence a purchase decision. In complex deals there may be several, covering technical, financial, and user perspectives. Identifying the real decision makers early prevents wasting time selling only to people who can influence but not actually approve the deal.`,
    points: [`A person with authority over the purchase decision.`, `Complex deals often have several decision makers.`, `Distinct from influencers who shape but cannot approve.`, `Identifying them early prevents wasted effort.`],
    why: `Selling to people without real authority feels productive but goes nowhere. Identifying the actual decision makers early ensures effort goes where it can produce a yes.`,
    rally: `Rally lets you tag decision makers within the buying committee and Rook flags deals where no decision maker is engaged, so reps do not mistake friendly influencers for the people who can actually approve.`,
    faqs: [{ q: `How do you identify the decision maker?`, a: `Ask directly about the decision process and who must approve, observe who others defer to, and confirm budget authority. In complex deals, map several decision makers across technical, financial, and user roles.` }, { q: `What is the difference between a decision maker and an influencer?`, a: `A decision maker has authority to approve or reject. An influencer shapes the decision through opinion or expertise but cannot approve it alone. Both matter, but only decision makers can commit the organization.` }] },

  { term: 'Gatekeeper', def: `A gatekeeper is a person who controls access to a decision maker, such as an assistant, office manager, or junior contact who screens outreach. Gatekeepers can block or enable a rep's path to the buyer. Treating them with respect and giving them a reason to help, rather than trying to bypass them, is the effective approach.`,
    points: [`Controls access to a decision maker.`, `Screens calls, emails, and meeting requests.`, `Can block or enable your path to the buyer.`, `Best handled with respect, not deception.`],
    why: `Gatekeepers decide whether your message reaches the buyer at all. Antagonizing or deceiving them backfires; earning their help opens the door that cold persistence alone cannot.`,
    rally: `Rally captures every contact including gatekeepers on the account, so the relationship history is visible. Rook can note who controls access and suggest multithreading paths that do not depend on one gate.`,
    faqs: [{ q: `How do you get past a gatekeeper?`, a: `Be respectful and honest, give a clear and relevant reason for reaching the decision maker, and enlist the gatekeeper's help rather than trying to trick them. Building rapport with them often opens the door faster than force.` }, { q: `Are gatekeepers always a barrier?`, a: `Not necessarily. A gatekeeper who understands and trusts you can become an ally, routing you to the right person and vouching for the relevance of your message. Respect turns them from barrier to bridge.` }] },

  { term: 'CPQ', def: `CPQ, or configure, price, quote, is software that helps sales teams quickly configure complex products, apply correct pricing and discounts, and generate accurate quotes. It automates rules that would otherwise be error-prone in spreadsheets, ensuring quotes are consistent, approved, and fast. CPQ is central to selling configurable or bundled offerings at scale.`,
    points: [`Automates product configuration, pricing, and quoting.`, `Enforces pricing rules, discounts, and approvals.`, `Reduces quote errors and turnaround time.`, `Essential for complex or bundled products.`],
    why: `Manual quoting for complex products is slow and error-prone, and a wrong quote can cost margin or credibility. CPQ makes quotes fast, accurate, and compliant with pricing policy.`,
    rally: `Rally includes quotes and CPQ so reps configure and price deals correctly inside the platform, with approval flows for exceptions. Rook can assemble a compliant quote from the deal's requirements in Studio.`,
    faqs: [{ q: `What does CPQ stand for?`, a: `Configure, Price, Quote. It refers to software that guides reps through configuring a product correctly, applying the right pricing and discounts, and producing an accurate, professional quote quickly.` }, { q: `Who needs CPQ?`, a: `Teams selling configurable, bundled, or complex products with many pricing rules and approval requirements. For simple, fixed-price products the overhead is unnecessary, but for complex offerings CPQ prevents costly quoting errors.` }] },

  { term: 'Quote', def: `A quote is a formal document a seller gives a buyer stating the products, quantities, prices, discounts, and terms for a proposed purchase. It represents a specific offer the buyer can accept to move toward a contract. Accurate, timely quotes are a critical step in closing, and delays or errors here cost deals.`,
    points: [`A formal offer stating products, prices, and terms.`, `A concrete step toward a contract.`, `Accuracy and speed directly affect close rates.`, `Often generated via CPQ for complex deals.`],
    why: `The quote is where interest becomes a concrete decision. A slow or inaccurate quote introduces friction and doubt at the worst moment, while a fast, correct one keeps momentum toward signature.`,
    rally: `Rally generates quotes from the deal's line items with correct pricing and approval routing, so quotes are fast and accurate. Rook can produce and send a quote from the deal context without manual assembly.`,
    faqs: [{ q: `What is the difference between a quote and a proposal?`, a: `A quote focuses on specific pricing and terms for products or services. A proposal is broader, often including the solution, value, approach, and pricing together. A quote can be part of a proposal.` }, { q: `Is a quote legally binding?`, a: `Generally a quote is an offer that becomes binding once the buyer accepts and both parties agree, though terms vary by jurisdiction and how the quote is worded. Formal contracts usually follow acceptance.` }] },

  { term: 'Proposal', def: `A proposal is a document that presents a seller's recommended solution to a buyer, typically covering the buyer's problem, the proposed approach, expected outcomes, pricing, and terms. It is more comprehensive than a quote and is used to make the full case for a purchase. A strong proposal reflects what discovery uncovered.`,
    points: [`Presents the full recommended solution and its value.`, `Covers problem, approach, outcomes, and pricing.`, `Broader and more persuasive than a quote.`, `Should reflect discovery findings, not a template.`],
    why: `A proposal is often what circulates internally to stakeholders you never meet. A tailored, outcome-focused proposal sells on your behalf; a generic one undermines everything the rep built in discovery.`,
    rally: `Rally's Studio builds proposals from the deal's context, pulling in the buyer's problem, solution, and pricing. Rook can draft a tailored proposal so reps send something specific and persuasive, not a boilerplate template.`,
    faqs: [{ q: `What should a sales proposal include?`, a: `A summary of the buyer's problem and goals, the recommended solution and approach, expected outcomes and value, pricing and terms, relevant proof like case studies, and clear next steps. Tailoring beats templates.` }, { q: `How is a proposal different from a quote?`, a: `A quote is a focused statement of pricing and terms. A proposal is a broader document that also makes the case for the solution and its value. Proposals persuade; quotes formalize the numbers.` }] },

  { term: 'Quote-to-Cash', def: `Quote-to-cash, or QTC, is the end-to-end business process that spans from generating a quote for a customer through configuring, pricing, contracting, ordering, billing, and collecting payment. It connects sales and finance, and streamlining it reduces errors, speeds revenue, and improves the customer experience from the moment a deal is priced to when cash arrives.`,
    points: [`End-to-end process from quote to collected payment.`, `Spans configuration, contract, order, billing, and cash.`, `Connects sales and finance operations.`, `Streamlining it speeds revenue and cuts errors.`],
    why: `Every handoff in quote-to-cash is a place for delay and error. A smooth process means deals convert to cash faster and customers experience a seamless transition from signing to being billed correctly.`,
    rally: `Rally connects quotes, CPQ, contracts, and billing in one platform, so quote-to-cash runs on a single source of truth rather than disconnected tools. Rook keeps the steps moving and flags where a deal stalls.`,
    faqs: [{ q: `What steps are in the quote-to-cash process?`, a: `Configuring the product, pricing and quoting, gaining approvals, contracting, order management, provisioning, invoicing and billing, and collecting payment. It covers everything from the initial quote to cash in the bank.` }, { q: `Why does quote-to-cash matter?`, a: `Because friction anywhere in it delays revenue and frustrates customers. A streamlined quote-to-cash process shortens the time from deal to cash, reduces billing errors, and improves the buying experience.` }] },

  { term: 'Discount', def: `A discount is a reduction from a product's list price offered to close a deal, reward volume, or match competition. While discounts can accelerate deals, excessive or habitual discounting erodes margin, trains buyers to expect it, and can signal weak value. Disciplined discounting uses approvals and thresholds to protect profitability.`,
    points: [`A reduction from list price to win or grow a deal.`, `Can accelerate closes but erodes margin.`, `Habitual discounting trains buyers to expect it.`, `Controlled with approval thresholds and policy.`],
    why: `Discounts are a fast lever that quietly destroys margin and value perception when overused. Governing them with thresholds and approvals keeps deals profitable and prevents a race to the bottom.`,
    rally: `Rally enforces discount thresholds with approval routing to the deal desk, so exceptions are visible and controlled. Rook can flag deals with unusually deep discounts and surface the margin impact before approval.`,
    faqs: [{ q: `Why is heavy discounting a problem?`, a: `It erodes margin, sets a precedent that buyers expect on renewal, and can signal that your list price is not credible. Habitual discounting undermines both profitability and the perceived value of the product.` }, { q: `How do you control discounting?`, a: `Set clear discount thresholds tied to approval levels, route exceptions through a deal desk, and give reps non-price tools to close. Visibility into margin impact helps everyone discount deliberately rather than reflexively.` }] },

  { term: 'Price Book', def: `A price book is a structured list of a company's products and services with their official prices, used to ensure reps quote consistent, approved pricing. It may include multiple price books for different regions, segments, or currencies. The price book is the pricing source of truth that feeds quotes, CPQ, and contracts.`,
    points: [`The official list of products and approved prices.`, `Can vary by region, segment, or currency.`, `The pricing source of truth for quotes and CPQ.`, `Keeps pricing consistent across the team.`],
    why: `Without a governed price book, reps quote inconsistent prices, undermining margin and trust. A single approved price book ensures every quote reflects the pricing the business intends.`,
    rally: `Rally uses a governed price book to drive quotes and CPQ, so line items always pull approved pricing. Rook builds quotes from the price book, keeping pricing consistent and reducing manual errors.`,
    faqs: [{ q: `Why use multiple price books?`, a: `To handle different regions, currencies, customer segments, or partner tiers that require distinct pricing. Multiple price books let a company maintain consistent, approved pricing across varied markets and deal types.` }, { q: `How does a price book relate to CPQ?`, a: `CPQ pulls prices from the price book when configuring and quoting, applying the correct approved rates and discount rules. The price book is the pricing foundation the quoting process depends on.` }] },

  { term: 'Line Item', def: `A line item is a single product or service entry on a quote, order, or invoice, with its own quantity, price, and terms. Breaking a deal into line items gives precise visibility into what is being sold, at what price, and how revenue and billing should be handled for each component of a larger deal.`,
    points: [`A single product or service entry on a deal.`, `Carries its own quantity, price, and terms.`, `Enables precise deal, billing, and revenue detail.`, `The building block of quotes, orders, and invoices.`],
    why: `Line items turn a lump-sum deal into structured data you can price, bill, forecast, and recognize accurately. Without them, reporting and billing lose the detail finance needs.`,
    rally: `Rally's deep deal object carries full line items, so bookings, quotes, billing, and revenue all derive from the same structured detail. Rook can break any deal into its line items for reporting on demand.`,
    faqs: [{ q: `Why do line items matter?`, a: `They provide the detail needed to price accurately, bill correctly, forecast by product, and recognize revenue per component. A deal recorded as a single lump sum loses the granularity finance and reporting require.` }, { q: `Can line items have different terms?`, a: `Yes. Different line items on one deal can have distinct quantities, prices, billing schedules, and recognition rules, such as a recurring subscription line alongside a one-time services line. That flexibility is why line items exist.` }] },

  { term: 'Renewal', def: `A renewal is when an existing customer extends their subscription or contract for another term. Renewals are the foundation of recurring-revenue businesses because retaining customers is far cheaper than acquiring new ones. Managing renewals proactively, with health monitoring and early engagement, protects revenue and creates opportunities to expand the account.`,
    points: [`An existing customer extending for another term.`, `The foundation of recurring-revenue economics.`, `Cheaper to secure than new acquisition.`, `Best managed proactively, not at the last minute.`],
    why: `Renewals are where retention becomes revenue. A business that neglects them until the contract ends risks churn it could have prevented and misses the natural moment to expand the account.`,
    rally: `Rally tracks renewal dates and account health, flagging at-risk renewals early. Rook can trigger a renewal play ahead of the date and surface expansion opportunities to turn a renewal into growth.`,
    faqs: [{ q: `When should you start working a renewal?`, a: `Well before the contract ends, often 90 days or more for larger accounts. Proactive engagement lets you address issues, demonstrate value, and discuss expansion rather than scrambling at the deadline.` }, { q: `What is the difference between renewal and retention?`, a: `Retention is the broad outcome of keeping customers. A renewal is the specific event of extending a contract. Strong renewal management is a primary driver of high retention.` }] },

  { term: 'Net Terms', def: `Net terms specify how long a customer has to pay an invoice after it is issued, such as Net 30 for payment within 30 days. They are a form of short-term credit sellers extend to buyers. Longer net terms can help close deals but delay cash collection, so they are balanced against working-capital needs.`,
    points: [`Define the payment window after invoicing, like Net 30.`, `A form of short-term credit to the buyer.`, `Longer terms ease buying but delay cash.`, `Balanced against working-capital needs.`],
    why: `Net terms affect both deal-making and cash flow. Generous terms can win price-sensitive buyers, but they push out collection, so finance and sales must balance flexibility against cash needs.`,
    rally: `Rally captures net terms on the deal and carries them into billing, so invoicing and collection reflect what was agreed. Rook can flag deals with unusually long terms that will strain cash timing.`,
    faqs: [{ q: `What does Net 30 mean?`, a: `Net 30 means the customer must pay the full invoice amount within 30 days of the invoice date. Net 60 and Net 90 extend that window to 60 or 90 days respectively.` }, { q: `Why do longer net terms matter to a business?`, a: `They delay when cash arrives, affecting working capital. A deal with Net 90 terms ties up revenue for three months, so businesses weigh the sales benefit against the cash-flow cost.` }] },

  { term: 'Statement of Work', def: `A statement of work, or SOW, is a document that defines the specific services, deliverables, timelines, and responsibilities for a project or engagement. It sits under a broader master agreement and spells out exactly what will be done. A clear SOW prevents scope disputes by making expectations explicit for both the customer and the provider.`,
    points: [`Defines services, deliverables, timeline, and responsibilities.`, `Sits under a master service agreement.`, `Prevents scope disputes by setting clear expectations.`, `Common in services and implementation engagements.`],
    why: `Vague scope is the root of most services conflicts. A precise SOW protects both sides by pinning down exactly what is delivered, by when, and who is responsible, before work begins.`,
    rally: `Rally can attach the SOW and its deliverables to the deal and carry them into projects, so what was sold matches what is delivered. Rook keeps SOW milestones visible alongside the deal record.`,
    faqs: [{ q: `What is the difference between an SOW and an MSA?`, a: `An MSA sets the overarching legal terms of the relationship. An SOW defines the specific work, deliverables, and timeline for a particular project under that MSA. One MSA can cover many SOWs.` }, { q: `What should a statement of work include?`, a: `The scope of work and deliverables, timelines and milestones, responsibilities of each party, acceptance criteria, and pricing or payment terms for the engagement. Clarity here prevents disputes later.` }] },

  { term: 'Master Service Agreement', def: `A master service agreement, or MSA, is a contract that establishes the general legal terms governing a business relationship, such as liability, confidentiality, payment, and dispute resolution. Specific projects are then handled through statements of work under the MSA. Negotiating the MSA once lets future deals move faster without renegotiating core terms.`,
    points: [`Sets the overarching legal terms of a relationship.`, `Covers liability, confidentiality, and dispute resolution.`, `Specific work is handled via SOWs under it.`, `Speeds future deals by settling core terms once.`],
    why: `Negotiating full legal terms on every deal is slow. An MSA settles the core terms once, so subsequent projects only need a short statement of work, dramatically accelerating repeat business.`,
    rally: `Rally can store the MSA on the account so its terms are visible across every future deal, and Rook can flag when a new deal falls under an existing MSA, letting reps skip straight to the SOW.`,
    faqs: [{ q: `Why use a master service agreement?`, a: `It settles the core legal terms of a relationship once, so future projects proceed under short statements of work without renegotiating liability, confidentiality, and payment each time. This speeds repeat deals considerably.` }, { q: `What is the difference between an MSA and a contract?`, a: `An MSA is a type of contract that governs the overall relationship. Individual engagements under it are defined by SOWs. The MSA is the umbrella; the SOWs are the specific projects it covers.` }] },

];

export default TERMS.map((t) => {
  const base = t.slug || kebab(t.term);
  return {
    slug: `what-is-${base}`,
    type: 'glossary',
    title: `What Is ${t.term}?`,
    metaTitle: `${t.term}: Definition, Examples, and Why It Matters (2026) | Rally`,
    metaDescription: `${t.term}: what it means, why it matters to revenue teams, and how Rally handles it in 2026.`,
    eyebrow: 'CRM glossary',
    h1: `What is ${t.term}?`,
    shortAnswer: t.def,
    intro:
      t.intro ||
      `${t.term} is a core concept in modern B2B revenue. Here is a clear, accurate definition, why it matters, and how Rally handles it.`,
    keyPoints: t.points,
    sections: [
      { h: 'Why it matters', body: t.why },
      { h: 'How Rally handles it', body: t.rally },
    ],
    faqs: t.faqs,
    published: PUB,
    updated: PUB,
  };
});
